use crate::model::{
    bytes_to_f32_slice, dequantize_f16_row, mat_vec_dispatch_batch, resolve_all, QType,
    ResolvedLocs, TransformerConfig,
};
#[cfg(not(target_arch = "wasm32"))]
use crate::residual_capture;

#[cfg(target_arch = "wasm32")]
use crate::loader::{TensorInfo, WeightBackend};
#[cfg(target_arch = "wasm32")]
use std::collections::HashMap;
#[cfg(target_arch = "wasm32")]
use std::sync::Arc;

#[cfg(target_arch = "wasm32")]
// wasm32: 8 is the *initial* capacity for short/single-token decode paths,
// to keep boot heap small. The lazy `ensure_*(seq_len)` callers grow each
// activation buffer on demand up to `seq_len * stride` for longer prompts
// (capped by `KV_MAX_SEQ_LEN = 128`). Only `batch_logits` stays pinned to
// `BATCH_CAPACITY * vocab_size` because (a) trisplit a/g/d workers never
// touch lm_head, and (b) growing logits at seq=128 alone would be
// `128 * 262144 * 4 = 128 MiB` — blowing the entire CF Workers isolate cap.
//
// Memory budget at seq_len=128 attn role: `batch_x = 128 * 5376 * 4 ≈ 2.6 MiB`
// + `batch_q ≈ 2.6 MiB` + `batch_k/v ≈ 1 MiB ea` + `batch_xb/xb2 ≈ 2.6 MiB ea`
// = ~14 MiB activations + residents (~76 MiB) + KV (~8 MiB) ≈ 100 MiB peak.
//
// History: Pre-fix BATCH_CAPACITY=4 panicked with `slice_index_fail` on
// 5-token prompts; pre-pre-fix BATCH_CAPACITY=16 boot-OOM'd because
// batch_logits alone was 16.8 MiB. Wave-21 long-prompt regression then
// surfaced the same `slice_index_fail` at seq=9 because BATCH_CAPACITY=8
// was a hard ceiling, not an initial allocation. Fix: `ensure_*` now grows
// to `max(BATCH_CAPACITY, seq_len) * stride` capped at `KV_MAX_SEQ_LEN`.
#[cfg(target_arch = "wasm32")]
const BATCH_CAPACITY: usize = 8;
#[cfg(not(target_arch = "wasm32"))]
const BATCH_CAPACITY: usize = 64;

// wasm32 dropped 128 → 96 (2026-05-03 wave-22 cliff fix). Frees
// (128-96) × 16 × 512 × 4 × 2 = 2 MiB per layer KV, gives the WASM
// heap ~4 MiB more breathing room for the lazy-grow activation set.
// Operational ceiling is enforced separately by the worker handler
// (MAX_SEQ_PER_CHUNK=64), so this just removes pre-alloc waste.
#[cfg(target_arch = "wasm32")]
const KV_MAX_SEQ_LEN: usize = 96;
#[cfg(not(target_arch = "wasm32"))]
const KV_MAX_SEQ_LEN: usize = 2048;

type Result<T> = std::result::Result<T, String>;

#[inline(always)]
fn gemma_mat_vec_f32_dispatch_batch(
    out: &mut [f32],
    x: &[f32],
    w: &[f32],
    rows: usize,
    cols: usize,
    n_batch: usize,
    out_stride: usize,
) {
    for b in 0..n_batch {
        let x_b = &x[b * cols..(b + 1) * cols];
        let out_b = &mut out[b * out_stride..b * out_stride + rows];
        mat_vec_f32(out_b, x_b, w, rows, cols);
    }
}

// ── GEMMA4_DBG: env-gated per-layer activation diagnostics ──────────────
//
// Set `GEMMA4_DBG=1` to emit one compact `eprintln!` line per layer (and per
// attention sub-op) localizing WHERE the activations blow up on a deployed
// run — purpose-built for the gemma4-arch f16-CUDA garbage-logits bug, where
// gemma3-arch serves coherently on the SAME f16 path. The probe walks a slice
// once for (max|abs|, NaN count, inf count); it is entirely behind the flag,
// so when `GEMMA4_DBG` is unset there is ZERO overhead (the OnceLock returns
// `false` and every `if gemma4_dbg() { … }` block is skipped — no slice walk,
// no formatting, no allocation).
//
// Grep the Cloud Run logs for `[g4dbg]` after deploying with GEMMA4_DBG=1.
// The FIRST line whose `max=` explodes (or `nan`/`inf` becomes nonzero)
// pinpoints the layer + sub-op + sliding-vs-global kind where the forward
// diverges, localizing the bug to a concrete code path.
#[cfg(not(target_arch = "wasm32"))]
#[inline]
fn gemma4_dbg() -> bool {
    use std::sync::OnceLock;
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| std::env::var("GEMMA4_DBG").is_ok())
}

/// GEMMA4_DBG numeric level (default 0). >=2 enables per-layer last-token
/// residual VALUE dumps (`[g4val]` lines: first 8 elements) for diffing the
/// GPU forward against an HF ground-truth per-layer trace — localizes a
/// gradual-precision-drift vs sharp-single-layer-divergence.
#[cfg(not(target_arch = "wasm32"))]
#[inline]
fn gemma4_dbg_level() -> u32 {
    use std::sync::OnceLock;
    static V: OnceLock<u32> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("GEMMA4_DBG")
            .ok()
            .and_then(|v| v.parse().ok())
            .unwrap_or(0)
    })
}
#[cfg(target_arch = "wasm32")]
#[inline]
fn gemma4_dbg_level() -> u32 {
    0
}

/// Whether to apply the per-layer `layer_output_scale` multiply to the FULL
/// residual stream. DEFAULT: OFF.
///
/// The gemma4-12b-it / -31b knots are DENSE Gemma3 that the knot encoder
/// relabels `arch="gemma4"` SOLELY because the GGUF carries a
/// `blk.<L>.layer_output_scale.weight` tensor. Multiplying the residual by
/// that per-layer scalar (~0.04–0.99, mean ≈ 0.6) was the prime suspect for
/// the invariant high-vocab-argmax garbage (lm_head → 236xxx of 262144,
/// identical on f16-GPU, f32-act GPU, and pure-CPU exact-f64). The working
/// in-repo TS reference `open-source/aether/src/gcp-layer-node.ts` — which
/// produces "Paris" — registers gemma4-12b as `architecture: 'gemma3'`, runs
/// the SAME embed sqrt-scale + raw-w norms + GeGLU + tanh softcap, and ends
/// each layer at `output[i] = afterAttn[i] + mlpOutput[i]` with NO per-layer
/// output scalar anywhere. HF dense Gemma3 (modeling_gemma3.py
/// `Gemma3DecoderLayer.forward`) likewise has no post-layer residual scale.
/// So applying it on the dense model corrupts the residual on every layer; the
/// tied-embedding lm_head then projects the corrupted hidden onto the
/// highest-norm embedding rows (the 236xxx tail) = the exact observed garbage.
///
/// CORRECTION (2026-06-22, live-verified): this scale is LOAD-BEARING, not spurious.
/// Disabling it makes the residual diverge to full NaN (the per-layer values run as
/// low as 0.0045, so they bound the residual). The 236xxx garbage was NOT caused by
/// this scale — it was the TOKENIZER (gemma SentencePiece mis-loaded via the qwen2
/// GPT-2-byte-BPE path, fixed separately). So this DEFAULTS ON; set
/// `GEMMA4_APPLY_LAYER_OUTPUT_SCALE=0` only for A/B diagnostics.
#[cfg(not(target_arch = "wasm32"))]
#[inline]
fn gemma4_apply_layer_output_scale() -> bool {
    use std::sync::OnceLock;
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("GEMMA4_APPLY_LAYER_OUTPUT_SCALE")
            .map(|v| !(v == "0" || v.eq_ignore_ascii_case("false")))
            .unwrap_or(true)
    })
}
#[cfg(target_arch = "wasm32")]
#[inline]
fn gemma4_apply_layer_output_scale() -> bool {
    false
}

/// One-pass activation health probe for GEMMA4_DBG. Returns
/// `(max_abs, nan_count, inf_count)`. `max_abs` ignores non-finite values so a
/// NaN/inf does not poison the magnitude readout (the counts surface those).
/// Only ever called from inside a `gemma4_dbg()` gate, so the walk cost is paid
/// solely when the flag is on.
#[cfg(not(target_arch = "wasm32"))]
fn g4_stats(xs: &[f32]) -> (f32, usize, usize) {
    let mut max_abs = 0.0f32;
    let mut nan = 0usize;
    let mut inf = 0usize;
    for &v in xs {
        if v.is_nan() {
            nan += 1;
        } else if v.is_infinite() {
            inf += 1;
        } else {
            let a = v.abs();
            if a > max_abs {
                max_abs = a;
            }
        }
    }
    (max_abs, nan, inf)
}

/// RMS + max|abs| of a vector — the standard "is this activation in range?"
/// readout. Used by the final-hidden→lm_head diagnostics so a single deploy
/// can show whether the final RMSNorm is doing the right thing (a healthy
/// gemma final-hidden RMS is O(1); a ballooned ~2.7e2 pre-norm RMS that the
/// final norm fails to tame points the bug at the readout path). Only ever
/// called under a `gemma4_dbg()` gate.
#[cfg(not(target_arch = "wasm32"))]
fn g4_rms_max(xs: &[f32]) -> (f32, f32) {
    let mut sum_sq = 0.0f64;
    let mut max_abs = 0.0f32;
    for &v in xs {
        sum_sq += (v as f64) * (v as f64);
        let a = v.abs();
        if a > max_abs {
            max_abs = a;
        }
    }
    let rms = if xs.is_empty() {
        0.0
    } else {
        (sum_sq / xs.len() as f64).sqrt() as f32
    };
    (rms, max_abs)
}

/// Forward-pass state for a Gemma3/Gemma4 station. Buffer sizes pick the
/// MAX of (sliding-layer dims, global-layer dims) so a single pipeline
/// can dispatch both layer kinds without re-allocation.
pub struct Gemma4Pipeline {
    pub config: TransformerConfig,
    pub locs: ResolvedLocs,
    pub knot: KnotWeights,
    pub kv_cache: KVCache,

    /// Residual stream (per-token hidden state, accumulated across layers).
    pub batch_x: Vec<f32>,
    /// Pre-projection / post-norm scratch for the attention path.
    pub batch_xb: Vec<f32>,
    /// O-projection output scratch.
    pub batch_xb2: Vec<f32>,
    /// Q output (per-token, per-head). Sized for the GLOBAL layer's
    /// (num_heads × global_head_dim) so sliding layers (smaller dim)
    /// also fit. Stride per token = `q_stride` below.
    pub batch_q: Vec<f32>,
    /// K output (per-token). Stride per token = `kv_stride` below.
    pub batch_k: Vec<f32>,
    /// V output (per-token). Same stride as K.
    pub batch_v: Vec<f32>,
    /// Gate / Up / Down FFN scratch.
    pub batch_hb: Vec<f32>,
    pub batch_hb2: Vec<f32>,
    /// Final logits buffer (one batch token = one set of vocab logits).
    pub batch_logits: Vec<f32>,
    /// Exact resident matvec memo for Gemma split-phase and LM-head paths.
    pub memo: matvec_memo::MatVecMemo,

    /// Per-token Q stride (=`num_heads * max(head_dim, global_head_dim)`).
    pub q_stride: usize,
    /// Per-token K/V stride (=`max(num_kv_heads, global_num_kv_heads) *
    /// max(head_dim, global_head_dim)`).
    pub kv_stride: usize,

    /// F-mesh-3 fix (opt-in via `GNOSIS_LM_HEAD_FP32=1`): pre-dequantized
    /// FP32 copy of `token_embd_weight` (tied lm_head). Lazily populated on
    /// first `lm_head_only` call when the env flag is set.
    ///
    /// **Why**: Aether v197-napi (the path that produces "Paris" on the
    /// canonical France prompt) front-loads Q4_K → FP32 dequant ONCE at
    /// boot, then runs FP32×FP32 matmul for every decode. The on-the-fly
    /// `mat_vec_q4k` path computes per-row dequant inside the dot product
    /// each call — Q4_K's 6-bit super-block scale rounding error is
    /// proportional to row magnitude, so high-norm rows (single-char
    /// SentencePiece pieces like S, C, L, …) accumulate ~5× the rounding
    /// bias of low-norm rows like `▁Paris`. The contextual signal *is*
    /// reaching the readout but cannot overcome the magnitude prior on
    /// the long tail. Pre-dequant kills the per-call accumulation drift.
    /// See `F_MESH_3_BYTE_FALLBACK_ROOT_CAUSE.md` for the full evidence.
    ///
    /// **Memory cost**: `vocab_size × hidden_dim × 4 bytes`. For
    /// gemma4-31b-it (vocab=262144, hidden=5376) this is **5.6 GiB**.
    /// - Native (Mac smoke / dev): fits.
    /// - Cloud Run coordinator (32 GiB / 8 CPU): fits — Aether already does this.
    /// - **CF Workers trisplit (128 MiB cap): does NOT fit.** Leave the
    ///   flag UNSET on cobordism workers; they'll keep the on-the-fly
    ///   Q4_K route and pay the magnitude-prior cost (the trisplit mesh
    ///   has its own per-hop quantization noise that may mask the bug).
    ///
    /// Production recommendation: set `GNOSIS_LM_HEAD_FP32=1` on native +
    /// Cloud Run coordinator deploys; leave unset on CF Workers.
    pub lm_head_fp32: Option<Vec<f32>>,

    // ── Wave-22 split-a Fix C: precomputed RoPE cos/sin tables ──────
    //
    // Gemma3/4 uses a dual-base RoPE scheme: sliding layers run with
    // `rope_local_base_freq` (10_000) and head_dim, global layers run
    // with `rope_theta` (1_000_000) and `global_head_dim`. We pre-bake
    // BOTH tables once at boot — the per-token rotate then collapses to
    // table lookups + multiply-add (no `theta.powf` / `sin_cos` host
    // trampoline calls in the hot loop). Memory cost is bounded by
    // `KV_MAX_SEQ_LEN * head_dim * 4` per table:
    //   - wasm sliding (96 × 256 × 4)  = 96 KiB
    //   - wasm global  (96 × 512 × 4)  = 192 KiB
    //   - wasm total                    = 288 KiB
    //   - native sliding (2048 × 256 × 4) = 2 MiB
    //   - native global  (2048 × 512 × 4) = 4 MiB
    // All well under the 128 MiB CF Worker isolate cap.
    //
    // Per the wave-22 split-a investigation (Fix C), this is the larger
    // win for rope_neox; SIMD on the rotate itself was deferred because
    // wasm simd128 has no gather opcode (only ~1.3× lift available).
    /// Precomputed cos/sin table for sliding (local) layers. Layout per
    /// [`crate::math::precompute_rope_table`]: `KV_MAX_SEQ_LEN × head_dim`
    /// f32, interleaved cos/sin per dim-pair. None when the model has
    /// no sliding pattern (all-global) — global table covers everything.
    pub rope_table_local: Option<Vec<f32>>,
    /// Precomputed cos/sin table for global-attention layers, sized for
    /// `KV_MAX_SEQ_LEN × global_head_dim`.
    pub rope_table_global: Vec<f32>,
    /// `head_dim` matching `rope_table_local`. Used for parity assertion
    /// at call sites (table layout depends on head_dim stride).
    pub rope_table_local_head_dim: usize,
    /// `head_dim` matching `rope_table_global`.
    pub rope_table_global_head_dim: usize,

    /// Last next-token logits produced by `forward_one`, for the fat-station
    /// `/generate` driver to read via `get_logits()`. Empty until first call.
    pub last_logits: Vec<f32>,

    // ── Gemma "Effective-4B" (E4B / gemma4 nested) extension ────────────
    //
    // E4B is a FOCUSED superset of the dense gemma4 path: it adds exactly
    // two pieces of machinery on top of the existing GeGLU / sandwich-norm
    // / sliding-vs-global / partial-RoPE / softcap pipeline:
    //   (A) PER-LAYER INPUT EMBEDDINGS (PLE)
    //   (B) KV-SHARED LAYERS
    // altup / laurel / MoE are NOT present in the target checkpoint
    // (trohrbaugh/gemma-4-E4B-it-heretic-ara) — verified absent from the
    // safetensors index (no altup_*/laurel_*/expert_* tensors). When this
    // flag is false EVERY field below is unused and the pipeline behaves
    // identically to a plain gemma4-31b knot. Gated entirely on the
    // presence of `embed_tokens_per_layer` in the knot metadata.
    pub e4b: bool,
    /// `hidden_size_per_layer_input` (Hp). E4B = 256.
    pub e4b_hp: usize,
    /// Resolved E4B top-level tensor refs (None when `!e4b`).
    pub e4b_embed_per_layer: Option<crate::model::TensorRef>,
    pub e4b_model_projection: Option<crate::model::TensorRef>,
    pub e4b_projection_norm: Option<crate::model::TensorRef>,
    /// Per-layer E4B tensor refs, indexed by layer. Empty when `!e4b`.
    pub e4b_input_gate: Vec<Option<crate::model::TensorRef>>,
    pub e4b_projection: Vec<Option<crate::model::TensorRef>>,
    pub e4b_post_input_norm: Vec<Option<crate::model::TensorRef>>,
    /// KV-share donor map, indexed by layer. `None` ⇒ the layer computes
    /// and caches its OWN K/V. `Some(d)` ⇒ the layer reuses the K/V that
    /// donor layer `d` already cached (same layer_type — sliding vs full).
    /// Empty when `!e4b`.
    pub e4b_kv_donor: Vec<Option<usize>>,
    /// Per-layer-input tensor for the CURRENT token, laid out [L][Hp].
    /// Recomputed at the top of each `forward_one`. Empty when `!e4b`.
    pub e4b_per_layer_inputs: Vec<f32>,
}

impl Gemma4Pipeline {
    /// Native-only constructor: opens the knot via mmap (or HTTP fallback)
    /// and bottoms out in `from_knot`.
    #[cfg(not(target_arch = "wasm32"))]
    pub fn new(path: String) -> Result<Self> {
        let knot = KnotWeights::load(&path).map_err(|e| format!("knot load: {:?}", e))?;
        Self::from_knot(knot)
    }

    /// Wasm host-driven constructor. Mirrors NativeLlamaPipeline::from_parts.
    /// `kv_base_layer` / `kv_num_layers` enable fluid-memory KV alloc: a
    /// trisplit worker that owns layer 17 passes (17, 1) and the cache
    /// allocates 1 slot's worth of K/V instead of the full 60. None falls
    /// back to (0, cfg.num_layers) — the legacy whole-model behavior.
    #[cfg(target_arch = "wasm32")]
    pub fn from_parts(
        backend: Arc<dyn WeightBackend>,
        metadata: HashMap<String, TensorInfo>,
        config: Option<KnotConfig>,
        payload_offset: usize,
        kv_base_layer: Option<usize>,
        kv_num_layers: Option<usize>,
    ) -> Result<Self> {
        let knot = KnotWeights::from_parts(backend, metadata, config, payload_offset);
        Self::from_knot_with_kv_range(knot, kv_base_layer, kv_num_layers)
    }

    pub fn from_knot(knot: KnotWeights) -> Result<Self> {
        Self::from_knot_with_kv_range(knot, None, None)
    }

    pub fn from_knot_with_kv_range(
        knot: KnotWeights,
        kv_base_layer: Option<usize>,
        kv_num_layers: Option<usize>,
    ) -> Result<Self> {
        let cfg = match &knot.config {
            Some(c) => TransformerConfig::from(c),
            None => return Err("Gemma4 knot must include a config block".to_string()),
        };
        if cfg.arch != "gemma3" && cfg.arch != "gemma4" {
            return Err(format!(
                "Gemma4Pipeline: arch={:?} not supported (expected gemma3|gemma4)",
                cfg.arch
            ));
        }

        // Pre-flight tensor presence check. resolve_all uses panic!()
        // for missing required tensors which on wasm32 collapses to an
        // opaque RuntimeError("unreachable") at the JS boundary — no
        // tensor name, no layer index, no panic message. Walk the
        // expected set up front and return the first missing name as a
        // Result so the worker can surface it cleanly. This is gemma4-
        // only; the qwen path keeps the panic for back-compat.
        let required_top = ["token_embd_weight", "output_norm_weight"];
        for name in required_top {
            if !knot.metadata.contains_key(name) {
                return Err(format!("preflight: missing top-level tensor {:?}", name));
            }
        }
        // Diagnostic: total tensor count + sample names. If JSON
        // round-trip lost entries we can spot it from the count alone.
        let total = knot.metadata.len();
        let sample: Vec<String> = knot
            .metadata
            .keys()
            .filter(|k| k.starts_with("blk_11_"))
            .cloned()
            .collect();
        for i in 0..cfg.num_layers {
            // Required per-layer tensors (V handled separately for global
            // layers via the V := K alias in resolve_all).
            let required = [
                format!("blk_{}_attn_norm_weight", i),
                format!("blk_{}_attn_q_weight", i),
                format!("blk_{}_attn_k_weight", i),
                format!("blk_{}_attn_output_weight", i),
                format!("blk_{}_ffn_norm_weight", i),
                format!("blk_{}_ffn_gate_weight", i),
                format!("blk_{}_ffn_up_weight", i),
                format!("blk_{}_ffn_down_weight", i),
            ];
            for name in &required {
                if !knot.metadata.contains_key(name) {
                    return Err(format!(
                        "preflight: missing layer-{} tensor {:?} (total tensors={}, blk_11_*={:?})",
                        i, name, total, sample,
                    ));
                }
            }
            // V or K-alias for V.
            let v_name = format!("blk_{}_attn_v_weight", i);
            let k_name = format!("blk_{}_attn_k_weight", i);
            if !knot.metadata.contains_key(&v_name) && !knot.metadata.contains_key(&k_name) {
                return Err(format!(
                    "preflight: layer {} missing both attn_v AND attn_k (V := K alias requires K)",
                    i
                ));
            }
        }

        // Reuse the kernel-wide tensor resolver. Returns LayerLocs with the
        // Gemma-only fields (q_norm/k_norm/post_attn_norm/post_ffw_norm/
        // layer_output_scale) populated when the knot carries them.
        let locs = resolve_all(&knot, &cfg);

        // Buffer sizing: max of sliding vs global shapes. Allocated once,
        // reused across layers regardless of `is_global(layer)`.
        let head_dim_max = cfg
            .global_head_dim
            .unwrap_or(cfg.head_dim)
            .max(cfg.head_dim);
        let q_stride = cfg.num_heads * head_dim_max;

        // Stride must accommodate BOTH sliding-window (n_kv * head_dim)
        // and global-attention (n_kv_global * head_dim_global) shapes.
        // For Gemma4-31B: sliding=16*256=4096, global=4*512=2048.
        let kv_stride = (cfg.num_kv_heads * cfg.head_dim).max(
            cfg.global_num_kv_heads.unwrap_or(cfg.num_kv_heads)
                * cfg.global_head_dim.unwrap_or(cfg.head_dim),
        );

        // ── E4B detection + tensor resolution ───────────────────────────
        //
        // E4B is identified by the presence of the PLE embedding table. The
        // knot encoder lowers HF dots → underscores, so HF
        // `model.language_model.embed_tokens_per_layer.weight` lands as
        // `embed_tokens_per_layer_weight`. We resolve every PLE tensor up
        // front; all are Option so a plain gemma4-31b knot leaves them None.
        let e4b = knot.metadata.contains_key("embed_tokens_per_layer_weight")
            || knot.metadata.contains_key("embed_tokens_per_layer.weight");
        let mut e4b_embed_per_layer = None;
        let mut e4b_model_projection = None;
        let mut e4b_projection_norm = None;
        let mut e4b_input_gate: Vec<Option<crate::model::TensorRef>> = Vec::new();
        let mut e4b_projection: Vec<Option<crate::model::TensorRef>> = Vec::new();
        let mut e4b_post_input_norm: Vec<Option<crate::model::TensorRef>> = Vec::new();
        let mut e4b_kv_donor: Vec<Option<usize>> = Vec::new();
        let mut e4b_hp: usize = 0;
        if e4b {
            // Helper to resolve a top-level tensor that may arrive under the
            // underscore or dot spelling. Returns (name, qtype) as a
            // TensorRef. We bypass `resolve_tensor` (which panics) and probe
            // metadata directly so a half-encoded knot returns None rather
            // than aborting the whole boot.
            let probe = |a: &str, b: &str| -> Option<crate::model::TensorRef> {
                for nm in [a, b] {
                    if let Some(info) = knot.metadata.get(nm) {
                        return Some(crate::model::TensorRef {
                            name: nm.to_string(),
                            qtype: crate::model::resolve_qtype(&info.tensor_type),
                        });
                    }
                }
                None
            };
            e4b_embed_per_layer = probe(
                "embed_tokens_per_layer_weight",
                "embed_tokens_per_layer.weight",
            );
            e4b_model_projection = probe(
                "per_layer_model_projection_weight",
                "per_layer_model_projection.weight",
            );
            e4b_projection_norm = probe(
                "per_layer_projection_norm_weight",
                "per_layer_projection_norm.weight",
            );

            // Hp = hidden_size_per_layer_input. Derive from the projection
            // norm tensor length (it is shape [Hp]). f32 ⇒ /4, f16 ⇒ /2.
            // Falls back to 256 (the E4B constant) if metadata is missing.
            e4b_hp = e4b_projection_norm
                .as_ref()
                .and_then(|t| knot.metadata.get(&t.name))
                .map(|info| {
                    let elem = match crate::model::resolve_qtype(&info.tensor_type) {
                        crate::model::QType::F16 => 2,
                        _ => 4,
                    };
                    (info.length as usize / elem).max(1)
                })
                .unwrap_or(256);

            // Per-layer PLE tensors + KV-share donor map.
            // first_shared = num_layers - num_kv_shared_layers. We don't have
            // num_kv_shared_layers in TransformerConfig (it is part of the
            // loader patch list), so derive the boundary by detecting which
            // layers actually carry their own k_proj cached output: in this
            // checkpoint EVERY layer has a k_proj weight (shared layers still
            // project Q but reuse cached K/V at runtime), so tensor presence
            // cannot distinguish. Instead we read the count from an env knob
            // if present, else fall back to the E4B-it constant (18).
            let num_kv_shared = std::env::var("GNOSIS_E4B_NUM_KV_SHARED")
                .ok()
                .and_then(|v| v.parse::<usize>().ok())
                .unwrap_or(18);
            let first_shared = cfg.num_layers.saturating_sub(num_kv_shared);

            // Layer-type map (sliding vs global/full) reuses is_global_layer
            // semantics: with sliding_window_pattern = 6 the full layers are
            // 5,11,17,…; everything else is sliding. The donor for a shared
            // layer is the LAST layer < first_shared of the SAME type.
            let is_global = |layer: usize| -> bool {
                match cfg.sliding_window_pattern {
                    Some(p) if p > 0 => (layer + 1).is_multiple_of(p),
                    _ => true,
                }
            };
            for i in 0..cfg.num_layers {
                e4b_input_gate.push(probe(
                    &format!("blk_{}_per_layer_input_gate_weight", i),
                    &format!("blk.{}.per_layer_input_gate.weight", i),
                ));
                e4b_projection.push(probe(
                    &format!("blk_{}_per_layer_projection_weight", i),
                    &format!("blk.{}.per_layer_projection.weight", i),
                ));
                e4b_post_input_norm.push(probe(
                    &format!("blk_{}_post_per_layer_input_norm_weight", i),
                    &format!("blk.{}.post_per_layer_input_norm.weight", i),
                ));
                if i >= first_shared && first_shared > 0 {
                    let want_global = is_global(i);
                    let donor = (0..first_shared)
                        .rev()
                        .find(|&d| is_global(d) == want_global);
                    e4b_kv_donor.push(donor);
                } else {
                    e4b_kv_donor.push(None);
                }
            }
        }

        let kv_base = kv_base_layer.unwrap_or(0);
        let kv_layers = kv_num_layers.unwrap_or(cfg.num_layers);
        let kv_cache = KVCache::with_base(
            kv_base,
            kv_layers,
            cfg.num_kv_heads.max(cfg.global_num_kv_heads.unwrap_or(0)),
            head_dim_max,
            KV_MAX_SEQ_LEN,
        );

        // ALL batch_* buffers are lazy-allocated on first use. Each
        // forward role (attn / gate-up / down / lm-head) only touches a
        // subset; eager allocation pinned the worker's heap unnecessarily
        // and tipped the gate-up role over the 128 MiB Cloudflare Workers
        // cap (ffn_gate + ffn_up residents alone are ~115 MB at Q4_K for
        // gemma4-31b's intermediate=21504 × hidden=5376). With lazy alloc
        // the gate-up role only ever grows batch_x/xb/xb2/hb/hb2; attn
        // grows batch_x/xb/xb2/q/k/v; lm-head grows batch_x/xb/logits.
        let batch_x: Vec<f32> = Vec::new();
        let batch_xb: Vec<f32> = Vec::new();
        let batch_xb2: Vec<f32> = Vec::new();
        let batch_q: Vec<f32> = Vec::new();
        let batch_k: Vec<f32> = Vec::new();
        let batch_v: Vec<f32> = Vec::new();
        let batch_hb: Vec<f32> = Vec::new();
        let batch_hb2: Vec<f32> = Vec::new();
        let batch_logits: Vec<f32> = Vec::new();

        // Wave-22 split-a Fix C: pre-bake RoPE cos/sin tables once at
        // boot. Sliding theta = rope_local_base_freq (default 10_000),
        // global theta = rope_theta. Sliding/global head_dim may differ
        // (Gemma4-31B: 256 vs 512). Build the global table unconditionally
        // (every model has it); skip the local table when there's no
        // sliding pattern.
        let global_head_dim = cfg.global_head_dim.unwrap_or(cfg.head_dim);
        let global_theta = cfg.rope_theta;
        // Gemma3/Gemma4 GLOBAL-layer linear RoPE position scaling: HF / the
        // Aether TS reference divide the position by `ropeScalingFactor`
        // (default 8.0) on global-attention layers ONLY. Bake it into the
        // global table (the table is read exclusively by global layers).
        // Sliding/local layers carry no scaling (factor 1.0).
        let global_pos_scale = cfg.rope_scaling_factor.filter(|f| *f > 0.0).unwrap_or(1.0);
        let rope_table_global = precompute_rope_table_scaled(
            KV_MAX_SEQ_LEN,
            global_head_dim,
            global_theta,
            global_pos_scale,
        );
        let (rope_table_local, rope_table_local_head_dim) = match cfg.sliding_window_pattern {
            Some(p) if p > 0 => {
                let local_theta = cfg.rope_local_base_freq.unwrap_or(cfg.rope_theta);
                let local_head_dim = cfg.head_dim;
                let table = precompute_rope_table(KV_MAX_SEQ_LEN, local_head_dim, local_theta);
                (Some(table), local_head_dim)
            }
            _ => (None, cfg.head_dim),
        };

        // Wave-23 Bug B (deeper fix, Path A): pre-grow WASM linear memory
        // above the worst-case per-call wasm-bindgen export size for
        // `get_batch_hb` BEFORE any JS-visible call runs.
        //
        // Why: wasm-bindgen 0.2.118 generates a Float32Array view cache
        // that is only invalidated on `byteLength === 0` (detached). On
        // Cloudflare Workers' V8 build the prior buffer is NOT detached
        // when `memory.grow` runs (byteLength stays > 0), so the cached
        // view keeps pointing into the stale (now too-small) buffer.
        // Even the wave-22 JS shim — which adds a `cache.buffer !==
        // wasm.memory.buffer` re-attach check — fails when `memory.grow`
        // happens DURING the export-copy (e.g., __wbindgen_malloc
        // reallocates while serializing the return value): `subarray` is
        // called on the freshly-attached view INSIDE the same call frame,
        // and the boundaries become invalid mid-copy.
        //
        // Path A fix: force the WASM heap to its worst-case peak at boot
        // by allocating two transient probes the size of a worst-case
        // `get_batch_hb` payload (one for the Rust `to_vec`, one for the
        // wasm-bindgen `__wbindgen_malloc` export-copy). dlmalloc keeps
        // the freed pages in its arena, so subsequent per-call
        // (`to_vec` + export-copy) allocations stay below the high-water
        // mark and never trigger a fresh `memory.grow`.
        //
        // Worst-case payload: MAX_SEQ_PER_CHUNK (worker-enforced=64) ×
        // intermediate_size. For gemma4-31b: 64 × 21504 = 1 376 256 f32
        // = 5.5 MiB per probe, 11 MiB transient. Both probes drop
        // immediately at end of scope; the heap retains the grown
        // pages for reuse.
        //
        // See docs/bug-b-split-b-length-fix.md (wave-21 analysis) and
        // docs/speculative-decode-N8-result.md (wave-23 trigger).
        #[cfg(target_arch = "wasm32")]
        {
            // 64 matches the worker handler's MAX_SEQ_PER_CHUNK ceiling
            // for /split-b. Using a literal (not KV_MAX_SEQ_LEN=96) keeps
            // the boot probe at the actual hot-path peak rather than the
            // KV-cache ceiling.
            const PROBE_SEQ_LEN: usize = 64;
            let probe_n = PROBE_SEQ_LEN * cfg.intermediate_size;
            // Two probes: one simulates `Vec<f32>` returned from
            // `get_batch_hb_residual`, the other simulates the
            // wasm-bindgen `__wbindgen_malloc` export-copy that runs in
            // the same call frame.
            let _probe_a: Vec<f32> = vec![0.0; probe_n];
            let _probe_b: Vec<f32> = vec![0.0; probe_n];
            // Touch the last byte of each so dead-code elimination
            // doesn't optimize the allocations away in release mode.
            // (Reading is sufficient; rustc cannot prove the read is
            // unobservable without inlining `Vec::new` semantics through
            // the entire constructor.)
            let _sink = _probe_a[probe_n - 1] + _probe_b[probe_n - 1];
            std::hint::black_box(_sink);
            // Probes drop here, returning their 11 MiB to the dlmalloc
            // free list. The high-water mark stays.
        }

        Ok(Self {
            config: cfg,
            locs,
            knot,
            kv_cache,
            batch_x,
            batch_xb,
            batch_xb2,
            batch_q,
            batch_k,
            batch_v,
            batch_hb,
            batch_hb2,
            batch_logits,
            memo: matvec_memo::MatVecMemo::new(),
            q_stride,
            kv_stride,
            // F-mesh-3: lm_head_fp32 cache stays None until first
            // lm_head_only call observes GNOSIS_LM_HEAD_FP32=1. Lazy
            // alloc keeps the 5.6 GiB cost out of trisplit boot.
            lm_head_fp32: None,
            // Wave-22 split-a Fix C: per-pipeline cos/sin tables.
            rope_table_local,
            rope_table_global,
            rope_table_local_head_dim,
            rope_table_global_head_dim: global_head_dim,
            last_logits: Vec::new(),
            e4b,
            e4b_hp,
            e4b_embed_per_layer,
            e4b_model_projection,
            e4b_projection_norm,
            e4b_input_gate,
            e4b_projection,
            e4b_post_input_norm,
            e4b_kv_donor,
            e4b_per_layer_inputs: Vec::new(),
        })
    }

    /// Single-token incremental decode for the fat-station `/generate` path.
    /// Mirrors gemma4-pipeline-smoke: dtype-aware embed (× sqrt(hidden) Gemma
    /// input scaling) → per-layer attn/ffn chunk forward at absolute `pos`
    /// (seq_len=1, KV cache incremental) → lm_head_only. Next-token logits are
    /// stashed in `last_logits` (read via `get_logits`). Callers feed strictly
    /// increasing `pos` (prefill 0..N, then decode N, N+1, …).
    pub fn forward_one(&mut self, token_id: u32, pos: usize) -> Result<()> {
        let hidden_dim = self.config.hidden_dim;
        let num_layers = self.config.num_layers;
        let embed_scale = (hidden_dim as f32).sqrt();
        let embed_bytes = self
            .knot
            .backend
            .fetch_tensor(&self.locs.embed.name)
            .map_err(|e| format!("fetch token_embd: {:?}", e))?;
        let mut row = vec![0.0f32; hidden_dim];
        let tok = token_id as usize;
        match self.locs.embed.qtype {
            QType::F32 => {
                let emb = bytes_to_f32_slice(&embed_bytes);
                let start = tok * hidden_dim;
                row.copy_from_slice(&emb[start..start + hidden_dim]);
            }
            QType::F16 => dequantize_f16_row(&mut row, &embed_bytes, tok, hidden_dim),
            QType::IQ2S => crate::iq_dequant::dequantize_iq2s_row(&mut row, &embed_bytes, tok, hidden_dim),
            QType::IQ3S => crate::iq_dequant::dequantize_iq3s_row(&mut row, &embed_bytes, tok, hidden_dim),
            QType::KAIJU1 => crate::kaiju_format::dequantize_kaiju1_row(&mut row, &embed_bytes, tok, hidden_dim),
            QType::Q4K => dequantize_q4k_row(&mut row, &embed_bytes, tok, hidden_dim),
            QType::Q5_0 => dequantize_q5_0_row(&mut row, &embed_bytes, tok, hidden_dim),
            QType::Q5K => dequantize_q5k_row(&mut row, &embed_bytes, tok, hidden_dim),
            QType::Q6K => dequantize_q6k_row(&mut row, &embed_bytes, tok, hidden_dim),
            QType::Q8_0 => dequantize_q8_0_row(&mut row, &embed_bytes, tok, hidden_dim),
        }
        drop(embed_bytes);
        for v in row.iter_mut() {
            *v *= embed_scale;
        }

        // GEMMA4_DBG: the embed sqrt(hidden) scale used + the post-embed token
        // RMS. The TS reference (`gcp-coordinator.ts:2312-2318`) applies the
        // SAME `Math.sqrt(hiddenDim)`; a mismatch here would shift the entire
        // residual stream. embed_qtype surfaces the tied-embedding dequant path.
        #[cfg(not(target_arch = "wasm32"))]
        if gemma4_dbg() {
            let (rms, mx) = g4_rms_max(&row);
            eprintln!(
                "[g4embed] token={token_id} embed_scale={embed_scale:.6e} \
                 embed_qtype={:?} post_embed_rms={rms:.4} max={mx:.4}",
                self.locs.embed.qtype
            );
        }

        // E4B (A): compute per-layer input embeddings for this token from the
        // (embed-scaled) main hidden state. No-op for plain gemma4 knots.
        if self.e4b {
            self.e4b_compute_per_layer_inputs(token_id, &row)?;
        }

        for layer in 0..num_layers {
            let is_first = layer == 0;
            let is_last = layer == num_layers - 1;
            let attn_input: &[f32] = if is_first { &row[..] } else { &[] };
            self.forward_range_attn_chunk(attn_input, layer, pos, 1, is_first)?;
            self.forward_range_ffn_gate_chunk(layer, 1)?;
            self.forward_range_ffn_up_chunk(layer, 1)?;
            let out = self.forward_range_ffn_down_chunk(layer, 1, is_last)?;
            // E4B (A): apply the per-layer-input correction AFTER the block.
            // forward_range_ffn_down_chunk leaves the post-MLP residual in
            // self.batch_x[..seq_len*hidden]; we add the gated PLE term there.
            if self.e4b {
                self.e4b_apply_per_layer_input(layer, 1)?;
            }
            if is_last {
                // Re-read the (now PLE-corrected) residual for the last layer
                // so lm_head consumes the corrected stream. `out` was captured
                // before the PLE add above.
                let corrected = if self.e4b {
                    self.get_residual(1)
                } else {
                    out
                };
                self.last_logits = self.lm_head_only(&corrected, 1)?;
            }
        }
        Ok(())
    }

    /// DISTRIBUTED ENTRY STATION: token ids -> initial residual hidden state.
    ///
    /// Mirrors the embed prologue of `forward_one` (the per-token dequant +
    /// `× sqrt(hidden_dim)` Gemma embed scale) but over a whole chunk of
    /// `token_ids`, returning the staged residual stream
    /// `[token_ids.len() * hidden_dim]` ready to hand to the first
    /// `/forward` station. No layer math runs here — it is exactly the
    /// `row` computation in `forward_one` lifted out per token.
    ///
    /// `start_pos` is accepted for signature symmetry with the Llama
    /// `embed_chunk` (the embedding itself is position-independent; RoPE /
    /// KV positions are applied later in `forward_range_chunk`).
    pub fn embed_chunk(&mut self, token_ids: &[u32], _start_pos: usize) -> Result<Vec<f32>> {
        self.embed(token_ids)
    }

    /// Token ids -> initial residual hidden state (Gemma embed lookup +
    /// `× sqrt(hidden_dim)` scale). Lifted verbatim from the embed prologue
    /// of `forward_one`, batched over `token_ids`.
    pub fn embed(&self, token_ids: &[u32]) -> Result<Vec<f32>> {
        let hidden_dim = self.config.hidden_dim;
        let embed_scale = (hidden_dim as f32).sqrt();
        let embed_bytes = self
            .knot
            .backend
            .fetch_tensor(&self.locs.embed.name)
            .map_err(|e| format!("fetch token_embd: {:?}", e))?;
        let mut out = vec![0.0f32; token_ids.len() * hidden_dim];
        let qtype = self.locs.embed.qtype;
        for (i, &token_id) in token_ids.iter().enumerate() {
            let tok = token_id as usize;
            let row = &mut out[i * hidden_dim..(i + 1) * hidden_dim];
            match qtype {
                QType::F32 => {
                    let emb = bytes_to_f32_slice(&embed_bytes);
                    let start = tok * hidden_dim;
                    row.copy_from_slice(&emb[start..start + hidden_dim]);
                }
                QType::F16 => dequantize_f16_row(row, &embed_bytes, tok, hidden_dim),
                QType::IQ2S => crate::iq_dequant::dequantize_iq2s_row(row, &embed_bytes, tok, hidden_dim),
                QType::IQ3S => crate::iq_dequant::dequantize_iq3s_row(row, &embed_bytes, tok, hidden_dim),
                QType::KAIJU1 => crate::kaiju_format::dequantize_kaiju1_row(row, &embed_bytes, tok, hidden_dim),
                QType::Q4K => dequantize_q4k_row(row, &embed_bytes, tok, hidden_dim),
                QType::Q5_0 => dequantize_q5_0_row(row, &embed_bytes, tok, hidden_dim),
                QType::Q5K => dequantize_q5k_row(row, &embed_bytes, tok, hidden_dim),
                QType::Q6K => dequantize_q6k_row(row, &embed_bytes, tok, hidden_dim),
                QType::Q8_0 => dequantize_q8_0_row(row, &embed_bytes, tok, hidden_dim),
            }
            for v in row.iter_mut() {
                *v *= embed_scale;
            }
        }
        drop(embed_bytes);
        Ok(out)
    }

    /// DISTRIBUTED LAYER STATION: residual hidden state + layer range
    /// `[start_layer, end_layer)` -> residual hidden state out.
    ///
    /// Reproduces the PLAIN per-layer transformer math of `forward_one`
    /// (GeGLU MLP, pre/post sandwich RMSNorms, attention logit tanh softcap
    /// inside `forward_range_attn_chunk`, sliding-vs-global attention
    /// dispatch via `is_global_layer`, partial-RoPE, per-layer dual-base
    /// RoPE theta, layer_output_scale), but:
    ///   (a) over `seq_len` tokens starting at absolute `start_pos`,
    ///   (b) only over layers `[start_layer, end_layer)`,
    ///   (c) staging the incoming residual into `batch_x` on the first layer
    ///       of the range (exactly how `forward_one` stages the embed row at
    ///       layer 0 via `forward_range_attn_chunk(.., is_first_layer=true)`),
    ///   (d) returning the resulting residual stream as `Vec<f32>`.
    ///
    /// The amplituhedron / Lipschitz / replay-cache machinery from the Llama
    /// `forward_range_chunk` is intentionally OMITTED (default-off in prod).
    ///
    /// Per-layer call sequence (identical order to `forward_one`'s loop body):
    ///   forward_range_attn_chunk(input?, layer, start_pos, seq_len, is_first)
    ///   forward_range_ffn_gate_chunk(layer, seq_len)
    ///   forward_range_ffn_up_chunk(layer, seq_len)
    ///   forward_range_ffn_down_chunk(layer, seq_len, is_last_in_range)
    pub fn forward_range_chunk(
        &mut self,
        input: &[f32],
        start_layer: usize,
        end_layer: usize,
        start_pos: usize,
        seq_len: usize,
    ) -> Result<Vec<f32>> {
        // E4B knots carry per-token per-layer-input (PLE) state that the
        // batched layer-range path cannot reconstruct from a bare residual;
        // they are not the dense gemma4 distributed target. Refuse rather
        // than silently dropping the PLE correction.
        if self.e4b {
            return Err(
                "forward_range_chunk: E4B (Gemma3n PLE) knots are not supported on the \
                 distributed layer-mesh path; use single-station /generate"
                    .to_string(),
            );
        }
        let hidden_dim = self.config.hidden_dim;
        let num_layers = self.config.num_layers;
        if input.len() != seq_len * hidden_dim {
            return Err(format!(
                "forward_range_chunk: input len {} != seq_len({}) * hidden_dim({})",
                input.len(),
                seq_len,
                hidden_dim
            ));
        }
        if start_layer > end_layer {
            return Err(format!(
                "forward_range_chunk: start_layer {} > end_layer {}",
                start_layer, end_layer
            ));
        }
        if end_layer > num_layers {
            return Err(format!(
                "forward_range_chunk: end_layer {} > num_layers {}",
                end_layer, num_layers
            ));
        }

        // Mirror `forward_one`'s loop body, restricted to [start_layer,
        // end_layer). `is_first` is true ONLY for the first layer of THIS
        // range — that is the layer that stages the incoming residual into
        // batch_x (forward_range_attn_chunk copies `input` over batch_x when
        // is_first_layer=true), exactly as forward_one stages the embed row
        // at layer 0.
        for layer in start_layer..end_layer {
            let is_first = layer == start_layer;
            // is_last is relative to THIS range — forward_range_ffn_down_chunk
            // only materialises the residual return buffer when true, so the
            // last layer of the range returns the staged residual to hand on.
            let is_last = layer == end_layer - 1;
            let attn_input: &[f32] = if is_first { input } else { &[] };
            self.forward_range_attn_chunk(attn_input, layer, start_pos, seq_len, is_first)?;
            self.forward_range_ffn_gate_chunk(layer, seq_len)?;
            self.forward_range_ffn_up_chunk(layer, seq_len)?;
            let out = self.forward_range_ffn_down_chunk(layer, seq_len, is_last)?;
            if is_last {
                return Ok(out);
            }
        }

        // Degenerate empty range (start_layer == end_layer): nothing ran, so
        // the residual is unchanged — return the input as-is.
        Ok(input.to_vec())
    }

    /// Next-token logits from the most recent `forward_one`.
    pub fn get_logits(&self) -> &[f32] {
        &self.last_logits
    }

    /// Serialize the `[layer_lo, layer_hi)` KV cache for the first `prefix_len`
    /// positions into a flat slab — the resume-anywhere transformer checkpoint.
    /// Byte/element layout is IDENTICAL to `NativeLlamaPipeline::get_kv_slab`
    /// (Gemma shares the same `kv_cache::KVCache` representation), so the
    /// fat-station `/kv-session/{save,load}` handlers treat Gemma exactly like
    /// the Llama transformer arm. Position/last-token stay HOST-owned (same
    /// ownership split as the Llama path), so they are NOT part of the slab.
    pub fn get_kv_slab(&self, layer_lo: usize, layer_hi: usize, prefix_len: usize) -> Vec<f32> {
        let kv_end = self.kv_cache.base_layer + self.kv_cache.num_layers;
        assert!(
            layer_lo < layer_hi && layer_hi <= kv_end,
            "bad KV layer range [{}, {}) for base_layer {} + num_layers {}",
            layer_lo,
            layer_hi,
            self.kv_cache.base_layer,
            self.kv_cache.num_layers
        );
        assert!(
            prefix_len <= self.kv_cache.max_seq_len,
            "prefix_len {} > KV max_seq_len {}",
            prefix_len,
            self.kv_cache.max_seq_len
        );

        let per_layer = self.kv_cache.num_kv_heads * prefix_len * self.kv_cache.head_dim;
        let layers = layer_hi - layer_lo;
        let mut slab = Vec::with_capacity(layers * per_layer * 2);

        for layer in layer_lo..layer_hi {
            let layer_offset = self.kv_cache.get_key_layer_offset(layer);
            for h in 0..self.kv_cache.num_kv_heads {
                let head_offset =
                    layer_offset + h * self.kv_cache.max_seq_len * self.kv_cache.head_dim;
                let end = head_offset + prefix_len * self.kv_cache.head_dim;
                slab.extend_from_slice(&self.kv_cache.keys[head_offset..end]);
            }
        }
        for layer in layer_lo..layer_hi {
            let layer_offset = self.kv_cache.get_val_layer_offset(layer);
            for h in 0..self.kv_cache.num_kv_heads {
                let head_offset =
                    layer_offset + h * self.kv_cache.max_seq_len * self.kv_cache.head_dim;
                let end = head_offset + prefix_len * self.kv_cache.head_dim;
                slab.extend_from_slice(&self.kv_cache.values[head_offset..end]);
            }
        }
        slab
    }

    /// Restore a slab produced by [`Self::get_kv_slab`] into the live KV cache.
    /// Mirror of `NativeLlamaPipeline::set_kv_slab`.
    pub fn set_kv_slab(
        &mut self,
        layer_lo: usize,
        layer_hi: usize,
        prefix_len: usize,
        slab: &[f32],
    ) {
        let kv_end = self.kv_cache.base_layer + self.kv_cache.num_layers;
        assert!(
            layer_lo < layer_hi && layer_hi <= kv_end,
            "bad KV layer range [{}, {}) for base_layer {} + num_layers {}",
            layer_lo,
            layer_hi,
            self.kv_cache.base_layer,
            self.kv_cache.num_layers
        );
        assert!(
            prefix_len <= self.kv_cache.max_seq_len,
            "prefix_len {} > KV max_seq_len {}",
            prefix_len,
            self.kv_cache.max_seq_len
        );
        let per_layer = self.kv_cache.num_kv_heads * prefix_len * self.kv_cache.head_dim;
        let expected = (layer_hi - layer_lo) * per_layer * 2;
        assert_eq!(
            slab.len(),
            expected,
            "KV slab len {} != expected {}",
            slab.len(),
            expected
        );

        let mut src = 0;
        for layer in layer_lo..layer_hi {
            let layer_offset = self.kv_cache.get_key_layer_offset(layer);
            for h in 0..self.kv_cache.num_kv_heads {
                let head_offset =
                    layer_offset + h * self.kv_cache.max_seq_len * self.kv_cache.head_dim;
                let end = head_offset + prefix_len * self.kv_cache.head_dim;
                let n = end - head_offset;
                self.kv_cache.keys[head_offset..end].copy_from_slice(&slab[src..src + n]);
                src += n;
            }
        }
        for layer in layer_lo..layer_hi {
            let layer_offset = self.kv_cache.get_val_layer_offset(layer);
            for h in 0..self.kv_cache.num_kv_heads {
                let head_offset =
                    layer_offset + h * self.kv_cache.max_seq_len * self.kv_cache.head_dim;
                let end = head_offset + prefix_len * self.kv_cache.head_dim;
                let n = end - head_offset;
                self.kv_cache.values[head_offset..end].copy_from_slice(&slab[src..src + n]);
                src += n;
            }
        }
    }

    /// Dtype-aware single-row dequant into `out` (len = `cols`). Mirrors the
    /// embed branch in `forward_one`; factored out so the E4B PLE path can
    /// reuse it for the `embed_tokens_per_layer` table.
    fn dequant_row(
        out: &mut [f32],
        bytes: &[u8],
        qtype: QType,
        row: usize,
        cols: usize,
    ) {
        match qtype {
            QType::F32 => {
                let f = bytes_to_f32_slice(bytes);
                let start = row * cols;
                out.copy_from_slice(&f[start..start + cols]);
            }
            QType::F16 => dequantize_f16_row(out, bytes, row, cols),
            QType::IQ2S => crate::iq_dequant::dequantize_iq2s_row(out, bytes, row, cols),
            QType::IQ3S => crate::iq_dequant::dequantize_iq3s_row(out, bytes, row, cols),
            QType::KAIJU1 => crate::kaiju_format::dequantize_kaiju1_row(out, bytes, row, cols),
            QType::Q4K => dequantize_q4k_row(out, bytes, row, cols),
            QType::Q5_0 => dequantize_q5_0_row(out, bytes, row, cols),
            QType::Q5K => dequantize_q5k_row(out, bytes, row, cols),
            QType::Q6K => dequantize_q6k_row(out, bytes, row, cols),
            QType::Q8_0 => dequantize_q8_0_row(out, bytes, row, cols),
        }
    }

    /// E4B (A) — PER-LAYER INPUT EMBEDDINGS.
    ///
    /// Computes `per_layer_inputs` for a single `token_id`, given the already
    /// embed-scaled main hidden state `x_embed` (len = hidden_dim). Result is
    /// stored in `self.e4b_per_layer_inputs`, laid out `[L][Hp]`.
    ///
    /// HF Gemma3n reference (`modeling_gemma3n.py`), verified via WebFetch:
    ///   ple   = embed_tokens_per_layer[token].reshape(L, Hp)   (× sqrt(Hp))
    ///   proj  = per_layer_projection_norm(
    ///             per_layer_model_projection(x_embed).reshape(L, Hp) × H**-0.5)
    ///   out   = (proj + ple) × rsqrt(2)
    /// The sqrt(Hp) embed scale is baked into the embedding row; we apply it
    /// here on dequant. `H**-0.5` is `hidden_dim ** -0.5`. The projection norm
    /// is a per-(layer-block) RMSNorm over the Hp slice (gemma4 raw-weight).
    fn e4b_compute_per_layer_inputs(&mut self, token_id: u32, x_embed: &[f32]) -> Result<()> {
        if !self.e4b {
            return Ok(());
        }
        let l = self.config.num_layers;
        let hp = self.e4b_hp;
        let h = self.config.hidden_dim;
        let total = l * hp;
        if self.e4b_per_layer_inputs.len() != total {
            self.e4b_per_layer_inputs.resize(total, 0.0);
        }

        // 1. ple = embed_tokens_per_layer[token] reshaped to (L, Hp), scaled
        //    by sqrt(Hp) (the embed_scale baked into the HF scaled embedding).
        let embed_ref = self
            .e4b_embed_per_layer
            .clone()
            .ok_or_else(|| "e4b: missing embed_tokens_per_layer".to_string())?;
        let embed_bytes = self
            .knot
            .backend
            .fetch_tensor(&embed_ref.name)
            .map_err(|e| format!("fetch embed_tokens_per_layer: {:?}", e))?;
        let mut ple = vec![0.0f32; total];
        Self::dequant_row(&mut ple, &embed_bytes, embed_ref.qtype, token_id as usize, total);
        drop(embed_bytes);
        let hp_scale = (hp as f32).sqrt();
        for v in ple.iter_mut() {
            *v *= hp_scale;
        }

        // 2. proj = per_layer_model_projection(x_embed) → (L*Hp), × H**-0.5.
        let mp_ref = self
            .e4b_model_projection
            .clone()
            .ok_or_else(|| "e4b: missing per_layer_model_projection".to_string())?;
        let mp_bytes = self
            .knot
            .backend
            .fetch_tensor(&mp_ref.name)
            .map_err(|e| format!("fetch per_layer_model_projection: {:?}", e))?;
        let mut proj = vec![0.0f32; total];
        // mat_vec: out[total] = W[total, H] · x_embed[H]
        mat_vec_dispatch_batch(
            &mut proj,
            x_embed,
            &mp_bytes,
            mp_ref.qtype,
            total,
            h,
            1,
            total,
        );
        drop(mp_bytes);
        let proj_scale = (h as f32).powf(-0.5);
        for v in proj.iter_mut() {
            *v *= proj_scale;
        }

        // 3. per_layer_projection_norm: RMSNorm over each Hp block of proj.
        let pn_ref = self
            .e4b_projection_norm
            .clone()
            .ok_or_else(|| "e4b: missing per_layer_projection_norm".to_string())?;
        let pn_bytes = self
            .knot
            .backend
            .fetch_tensor(&pn_ref.name)
            .map_err(|e| format!("fetch per_layer_projection_norm: {:?}", e))?;
        let pn_v = bytes_to_f32_slice(&pn_bytes);
        let shift = self.gemma_norm_shift();
        let eps = self.config.rms_norm_eps;
        let mut normed = vec![0.0f32; hp];
        for layer in 0..l {
            let blk = &mut proj[layer * hp..(layer + 1) * hp];
            gemma_rms_norm(&mut normed, blk, &pn_v, eps, shift);
            blk.copy_from_slice(&normed);
        }
        drop(pn_bytes);

        // 4. out = (proj + ple) × rsqrt(2).
        let inv_sqrt2 = std::f32::consts::FRAC_1_SQRT_2;
        for i in 0..total {
            self.e4b_per_layer_inputs[i] = (proj[i] + ple[i]) * inv_sqrt2;
        }
        Ok(())
    }

    /// E4B (A) — apply the per-layer-input correction for `layer` to the
    /// residual stream AFTER the transformer block (post attn+ffn). Operates
    /// on `seq_len` tokens in `self.batch_x`.
    ///
    /// HF reference (no-altup specialization — `first_prediction` == h):
    ///   g  = post_per_layer_input_norm(
    ///          per_layer_projection(
    ///            gelu_tanh(per_layer_input_gate(h)) × per_layer_input[layer]))
    ///   h += g
    /// per_layer_input_gate: Linear [Hp, H] (h → Hp).
    /// per_layer_projection: Linear [H, Hp] (Hp → h).
    /// post_per_layer_input_norm: RMSNorm over hidden_dim.
    fn e4b_apply_per_layer_input(&mut self, layer: usize, seq_len: usize) -> Result<()> {
        if !self.e4b {
            return Ok(());
        }
        let h = self.config.hidden_dim;
        let hp = self.e4b_hp;
        let eps = self.config.rms_norm_eps;
        let shift = self.gemma_norm_shift();

        let gate_ref = match self.e4b_input_gate[layer].clone() {
            Some(r) => r,
            None => return Ok(()), // layer carries no PLE correction
        };
        let proj_ref = self
            .e4b_projection[layer]
            .clone()
            .ok_or_else(|| format!("e4b: layer {} missing per_layer_projection", layer))?;
        let norm_ref = self
            .e4b_post_input_norm[layer]
            .clone()
            .ok_or_else(|| format!("e4b: layer {} missing post_per_layer_input_norm", layer))?;

        let gate_bytes = self
            .knot
            .backend
            .fetch_tensor(&gate_ref.name)
            .map_err(|e| format!("fetch per_layer_input_gate: {:?}", e))?;
        let proj_bytes = self
            .knot
            .backend
            .fetch_tensor(&proj_ref.name)
            .map_err(|e| format!("fetch per_layer_projection: {:?}", e))?;
        let norm_bytes = self
            .knot
            .backend
            .fetch_tensor(&norm_ref.name)
            .map_err(|e| format!("fetch post_per_layer_input_norm: {:?}", e))?;
        let norm_v = bytes_to_f32_slice(&norm_bytes);

        let pli = &self.e4b_per_layer_inputs[layer * hp..(layer + 1) * hp];
        let mut gated = vec![0.0f32; hp];
        let mut g = vec![0.0f32; h];
        let mut g_normed = vec![0.0f32; h];
        for i in 0..seq_len {
            let x_i = &self.batch_x[i * h..(i + 1) * h];
            // gate: Hp = W_gate[Hp, H] · x
            mat_vec_dispatch_batch(&mut gated, x_i, &gate_bytes, gate_ref.qtype, hp, h, 1, hp);
            // gelu_tanh(gate) * per_layer_input[layer]
            gelu_inplace(&mut gated);
            for j in 0..hp {
                gated[j] *= pli[j];
            }
            // projection: H = W_proj[H, Hp] · gated
            mat_vec_dispatch_batch(&mut g, &gated, &proj_bytes, proj_ref.qtype, h, hp, 1, h);
            // post_per_layer_input_norm (RMSNorm over hidden_dim)
            gemma_rms_norm(&mut g_normed, &g, &norm_v, eps, shift);
            // residual add
            let x_mut = &mut self.batch_x[i * h..(i + 1) * h];
            for j in 0..h {
                x_mut[j] += g_normed[j];
            }
        }
        Ok(())
    }

    pub fn memo_enable(&mut self, on: bool) {
        self.memo.set_enabled(on);
    }

    pub fn memo_set_tau_squared(&mut self, tau_sq: f32) {
        self.memo.set_tau_squared(tau_sq);
    }

    pub fn memo_set_max_entries(&mut self, n: usize) {
        self.memo.set_max_entries(n);
    }

    pub fn memo_clear(&mut self) {
        self.memo.clear();
    }

    pub fn memo_stats(&self) -> (u64, u64, u64) {
        self.memo.stats()
    }

    /// True when `layer` is a global-attention layer (Gemma3/4: every Nth,
    /// where N = `sliding_window_pattern`; the LAST layer in each pattern
    /// is global). For pattern=6, layers 5, 11, 17, 23, … are global.
    /// When `sliding_window_pattern` is None the model has no sliding
    /// attention and ALL layers are global.
    #[inline]
    pub fn is_global_layer(&self, layer: usize) -> bool {
        match self.config.sliding_window_pattern {
            Some(p) if p > 0 => (layer + 1).is_multiple_of(p),
            _ => true,
        }
    }

    /// Gemma RMSNorm gamma convention: whether to apply `(1 + w)` (HF stores
    /// the gamma as a delta from identity; llama.cpp adds 1.0 at load for ALL
    /// gemma variants) vs raw `w`. Default = `arch == "gemma3"`. The
    /// `GEMMA4_FORCE_SHIFT` env var overrides for deterministic bisection:
    ///   GEMMA4_FORCE_SHIFT=1 → always shift, =0 → never shift.
    #[inline]
    pub fn gemma_norm_shift(&self) -> bool {
        match std::env::var("GEMMA4_FORCE_SHIFT").ok().as_deref() {
            Some("1") => true,
            Some("0") => false,
            _ => self.config.arch == "gemma3",
        }
    }

    /// Effective head_dim for a given layer (global vs sliding).
    #[inline]
    pub fn layer_head_dim(&self, layer: usize) -> usize {
        if self.is_global_layer(layer) {
            self.config.global_head_dim.unwrap_or(self.config.head_dim)
        } else {
            self.config.head_dim
        }
    }

    /// Effective num_kv_heads for a given layer.
    #[inline]
    pub fn layer_num_kv_heads(&self, layer: usize) -> usize {
        if self.is_global_layer(layer) {
            self.config
                .global_num_kv_heads
                .unwrap_or(self.config.num_kv_heads)
        } else {
            self.config.num_kv_heads
        }
    }

    /// RoPE base frequency for a given layer.
    ///
    /// Gemma 3 + 4 use a dual-base scheme: sliding-window-attention
    /// layers use `rope_local_base_freq` (10 000), global layers use
    /// `rope_theta` (1 000 000). Aether's deployed code mirrors this:
    ///
    ///   theta = ropeLocalBaseFreq
    ///     ? (isGlobalLayer ? ropeTheta : ropeLocalBaseFreq)
    ///     : (ropeTheta || 10000)
    ///
    /// `rope_scaling_factor` is NOT multiplied into theta — that earlier
    /// experiment (`rope_theta * 8 = 8M`) is mathematically NOT equivalent
    /// to the real op and broke the frequency spectrum. The CORRECT op is
    /// what Gemma3/Gemma4 globals actually do: divide the *position* by
    /// `ropeScalingFactor` (default 8.0). Aether `gcp-layer-node.ts` gates
    /// it on `isGemma3 && isGlobalLayer` (`layerScaling = isGlobalLayer ?
    /// ropeScalingFactor : 1.0`) and applies it as `scaledPosition =
    /// position / ropeScalingFactor` inside `applyRoPE`. This position
    /// scaling is implemented here (NOT in `layer_rope_theta`): baked into
    /// `rope_table_global` via `precompute_rope_table_scaled` for the
    /// cached fast path, and applied to `pos_f` for the non-cached
    /// fallback. Omitting it collapses global-layer angles and the model
    /// degenerates into a single-token repetition loop.
    #[inline]
    pub fn layer_rope_theta(&self, layer: usize) -> f32 {
        if self.is_global_layer(layer) {
            self.config.rope_theta
        } else {
            self.config
                .rope_local_base_freq
                .unwrap_or(self.config.rope_theta)
        }
    }

    /// Number of head_dim elements that participate in RoPE (the rest are
    /// copied through unchanged). When `rope_partial_factor` is None all
    /// dims rotate. Gemma 4 uses partial RoPE ONLY on global layers.
    #[inline]
    pub fn layer_rope_n_rot(&self, layer: usize) -> usize {
        let hd = self.layer_head_dim(layer);
        if !self.is_global_layer(layer) {
            return hd;
        }
        // GOLDEN-DIFF FIX (2026-06-22): HONOR `rope_partial_factor` as the knot
        // config reports it. The prior code force-rewrote `f == 1.0 → 0.25`,
        // which rotated only the first 25% of each global head's `head_dim`
        // while the Paris-producing reference rotates the FULL head_dim.
        //
        // The reference `open-source/aether/src/gcp-layer-node.ts` applies RoPE
        // over the entire `headDim` on EVERY gemma layer — sliding AND global —
        // and never consults `ropePartialFactor` in its attention/RoPE path
        // (the field exists in its config but is unused). A `rope_partial_factor`
        // of 1.0 therefore means "rotate the whole head_dim" (n_rot == head_dim),
        // exactly matching the reference. The knot encoder
        // (`bitwise/scripts/encode-llama-knot.ts`) sets
        // `rope_partial_factor = rope.dimension_count / attention.key_length`
        // from the GGUF; for the gemma4 knots whose GGUF reports
        // `dimension_count == key_length` that is 1.0 == full rotation — its own
        // comment says so ("→ full rotation, so rope_partial_factor = 1.0").
        //
        // Forcing 1.0 → 0.25 mis-rotated 75% of each global head's Q/K phase,
        // collapsing positional discrimination on the long-range (global) layers
        // → flat attention → INPUT-BLIND, POSITION-BLIND repetition ("and and
        // and …"). It was invariant to the attn_scale and RoPE position-scaling
        // fixes because the rotation EXTENT — not the angle/temperature — was
        // wrong. A genuine sub-1.0 partial factor (e.g. a knot that really does
        // rotate 25%) is still honored.
        match self.config.rope_partial_factor {
            Some(f) if f > 0.0 && f < 1.0 => {
                let n = ((hd as f32) * f) as usize;
                // Round down to even — RoPE always rotates pairs.
                n & !1
            }
            _ => hd,
        }
    }

    // ── Lazy buffer growth ────────────────────────────────────────────
    //
    // Each forward role grows only the buffers it touches. The default
    // capacity is `BATCH_CAPACITY` positions; callers that know `seq_len`
    // pass it via `ensure_*_seq` and the buffer grows to fit. This is the
    // wave-21 long-prompt fix: pre-wave-21 the buffers were pinned to
    // BATCH_CAPACITY=8 and seq_len ≥ 9 OOB'd in the per-position write
    // loops with `core::slice::index::slice_index_fail`.
    //
    // The grow strategy: target = max(BATCH_CAPACITY, seq_len) × stride.
    // We never shrink; once a worker isolate has paid for a long-prompt
    // buffer it keeps it for the rest of its lifetime. CF Workers cap is
    // 128 MiB; at seq_len=128 the activation total is ~14 MiB (see header
    // comment), well within budget.
    #[inline]
    fn cap_for(seq_len: usize) -> usize {
        if seq_len > BATCH_CAPACITY {
            seq_len
        } else {
            BATCH_CAPACITY
        }
    }
    #[inline]
    fn ensure_x(&mut self) {
        self.ensure_x_seq(BATCH_CAPACITY);
    }
    #[inline]
    fn ensure_xb(&mut self) {
        self.ensure_xb_seq(BATCH_CAPACITY);
    }
    #[inline]
    #[allow(dead_code)]
    fn ensure_xb2(&mut self) {
        self.ensure_xb2_seq(BATCH_CAPACITY);
    }
    #[inline]
    #[allow(dead_code)]
    fn ensure_qkv(&mut self) {
        self.ensure_qkv_seq(BATCH_CAPACITY);
    }
    #[inline]
    #[allow(dead_code)]
    fn ensure_hb(&mut self) {
        self.ensure_hb_seq(BATCH_CAPACITY);
    }
    #[inline]
    #[allow(dead_code)]
    fn ensure_hb2(&mut self) {
        self.ensure_hb2_seq(BATCH_CAPACITY);
    }
    #[inline]
    fn ensure_x_seq(&mut self, seq_len: usize) {
        let n = Self::cap_for(seq_len) * self.config.hidden_dim;
        if self.batch_x.len() < n {
            self.batch_x.resize(n, 0.0);
        }
    }
    #[inline]
    fn ensure_xb_seq(&mut self, seq_len: usize) {
        let n = Self::cap_for(seq_len) * self.config.hidden_dim.max(self.q_stride);
        if self.batch_xb.len() < n {
            self.batch_xb.resize(n, 0.0);
        }
    }
    #[inline]
    fn ensure_xb2_seq(&mut self, seq_len: usize) {
        let n = Self::cap_for(seq_len) * self.config.hidden_dim;
        if self.batch_xb2.len() < n {
            self.batch_xb2.resize(n, 0.0);
        }
    }
    #[inline]
    fn ensure_qkv_seq(&mut self, seq_len: usize) {
        let cap = Self::cap_for(seq_len);
        let q_n = cap * self.q_stride;
        let kv_n = cap * self.kv_stride;
        if self.batch_q.len() < q_n {
            self.batch_q.resize(q_n, 0.0);
        }
        if self.batch_k.len() < kv_n {
            self.batch_k.resize(kv_n, 0.0);
        }
        if self.batch_v.len() < kv_n {
            self.batch_v.resize(kv_n, 0.0);
        }
    }
    #[inline]
    fn ensure_hb_seq(&mut self, seq_len: usize) {
        let n = Self::cap_for(seq_len) * self.config.intermediate_size;
        if self.batch_hb.len() < n {
            self.batch_hb.resize(n, 0.0);
        }
    }
    #[inline]
    fn ensure_hb2_seq(&mut self, seq_len: usize) {
        let n = Self::cap_for(seq_len) * self.config.intermediate_size;
        if self.batch_hb2.len() < n {
            self.batch_hb2.resize(n, 0.0);
        }
    }

    /// Stage `input` into batch_x for a fresh forward pass. Mirrors the
    /// Qwen path's `is_first_layer=true` behavior.
    pub fn set_batch_x(&mut self, input: &[f32]) {
        // Grow batch_x to fit input length so long-prompt callers don't
        // get silently truncated at BATCH_CAPACITY (wave-21 fix).
        let hidden_dim = self.config.hidden_dim.max(1);
        let seq_len = input.len() / hidden_dim;
        self.ensure_x_seq(seq_len);
        let n = input.len().min(self.batch_x.len());
        self.batch_x[..n].copy_from_slice(&input[..n]);
    }

    pub fn get_residual(&self, seq_len: usize) -> Vec<f32> {
        let n = seq_len * self.config.hidden_dim;
        if n > self.batch_x.len() {
            // Lazy buffer wasn't grown — caller asked for residual on a
            // worker that never ran a forward pass. Return zeros at the
            // requested length rather than panicking.
            return vec![0.0; n];
        }
        #[cfg(not(target_arch = "wasm32"))]
        residual_capture::maybe_capture_on_batch_x_export(
            &self.batch_x[..n],
            seq_len,
            self.config.hidden_dim,
        );
        self.batch_x[..n].to_vec()
    }

    pub fn get_batch_xb_residual(&self, seq_len: usize) -> Vec<f32> {
        let n = seq_len * self.config.hidden_dim;
        if n > self.batch_xb.len() {
            return vec![0.0; n];
        }
        self.batch_xb[..n].to_vec()
    }

    pub fn set_batch_xb_residual(&mut self, input: &[f32]) {
        // Derive seq_len from the input length so the buffer grows past
        // BATCH_CAPACITY for long-prompt /split-b requests (wave-21 fix).
        // Input is `seq_len * hidden_dim` per the get_batch_xb_residual
        // contract; buffer stride is `max(hidden_dim, q_stride)` so the
        // grow target is computed in `ensure_xb_seq` from seq_len.
        let hidden_dim = self.config.hidden_dim.max(1);
        let seq_len = input.len() / hidden_dim;
        self.ensure_xb_seq(seq_len);
        assert!(
            input.len() <= self.batch_xb.len(),
            "batch_xb input len {} > batch_xb.len {}",
            input.len(),
            self.batch_xb.len()
        );
        self.batch_xb[..input.len()].copy_from_slice(input);
    }

    pub fn get_batch_hb_residual(&self, seq_len: usize) -> Vec<f32> {
        let n = seq_len * self.config.intermediate_size;
        if n > self.batch_hb.len() {
            return vec![0.0; n];
        }
        self.batch_hb[..n].to_vec()
    }

    pub fn set_batch_hb_residual(&mut self, input: &[f32]) {
        // Derive seq_len from the input length so the buffer grows past
        // BATCH_CAPACITY for long-prompt /split-c requests (wave-21 fix).
        let intermediate_size = self.config.intermediate_size.max(1);
        let seq_len = input.len() / intermediate_size;
        self.ensure_hb_seq(seq_len);
        assert!(
            input.len() <= self.batch_hb.len(),
            "batch_hb input len {} > batch_hb.len {}",
            input.len(),
            self.batch_hb.len()
        );
        self.batch_hb[..input.len()].copy_from_slice(input);
    }

    /// Fused split-c setter: takes the already-concatenated
    /// `[batch_x | batch_hb]` host buffer in ONE call. Splits via slice
    /// math (no second copy) and dispatches to the existing
    /// `set_batch_x` / `set_batch_hb_residual` helpers — preserving
    /// `ensure_x_seq` / `ensure_hb_seq` grow semantics and the
    /// `copy_from_slice` validations.
    ///
    /// Wave-22 SPLIT_C_BOTTLENECK_INVESTIGATION Fix A: reduces
    /// wasm-bindgen calls 2 → 1 and `__wbindgen_malloc` calls 2 → 1.
    /// Predicted +6.0% TPS (0.02361 → 0.02502 on gemma4-31b trisplit).
    pub fn set_batch_x_and_hb(&mut self, combined: &[f32], hidden_dim: usize, seq_len: usize) {
        let intermediate_size = self.config.intermediate_size.max(1);
        let x_len = seq_len * hidden_dim;
        let hb_len = seq_len * intermediate_size;
        let expected = x_len + hb_len;
        assert!(
            combined.len() == expected,
            "set_batch_x_and_hb: combined.len {} != expected {} (seq_len {} × hidden_dim {} + seq_len × intermediate_size {})",
            combined.len(),
            expected,
            seq_len,
            hidden_dim,
            intermediate_size
        );
        // Reuse existing helpers via slice math — no extra copy. The
        // helpers handle ensure_*_seq buffer growth and the internal
        // copy_from_slice into the persistent batch_* buffers.
        self.set_batch_x(&combined[..x_len]);
        self.set_batch_hb_residual(&combined[x_len..]);
    }

    /// Split phase 1: attention. Reads input from batch_x (when
    /// `is_first_layer=true`, copies `input` over batch_x first), runs
    /// Gemma3/4 attention, writes the post-attention output back into
    /// batch_x (residual already added) and the post-attn-norm into
    /// batch_xb (ready for the FFN gate/up matmuls).
    pub fn forward_range_attn_chunk(
        &mut self,
        input: &[f32],
        layer: usize,
        start_pos: usize,
        seq_len: usize,
        is_first_layer: bool,
    ) -> Result<()> {
        // Hoist the Gemma norm-shift flag before any &mut self.batch_* borrows.
        let gemma_shift = self.gemma_norm_shift();
        // Attn role grows {x, xb, xb2, q, k, v}. Skip hb/hb2/logits.
        // Pass `seq_len` so the buffers grow past the BATCH_CAPACITY=8
        // default for long-prompt requests (wave-21 fix).
        self.ensure_x_seq(seq_len);
        self.ensure_xb_seq(seq_len);
        self.ensure_xb2_seq(seq_len);
        self.ensure_qkv_seq(seq_len);
        let cfg = &self.config;
        let hidden_dim = cfg.hidden_dim;

        if is_first_layer {
            self.batch_x[..seq_len * hidden_dim].copy_from_slice(input);
        }

        // GEMMA4_DBG: would this layer's projection GEMMs route through the f16
        // CUDA path? A matmul takes the GPU f16 path iff the cuda feature is
        // built, the GPU is engaged for this token count, AND the f16 weight
        // dtype is selected. Computed once here (cheap), logged per layer below.
        // Outside the `cuda` feature this is always false (CPU path).
        #[cfg(not(target_arch = "wasm32"))]
        let used_f16_cuda: bool = {
            #[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
            {
                crate::cuda_matmul::weight_dtype_f16() && crate::cuda_matmul::gpu_wants(seq_len)
            }
            #[cfg(not(feature = "cuda"))]
            {
                false
            }
        };

        let lw = &self.locs.layers[layer];
        let head_dim = self.layer_head_dim(layer);
        let n_kv = self.layer_num_kv_heads(layer);
        let qkv_dim = cfg.num_heads * head_dim;
        let kv_dim = n_kv * head_dim;
        let theta = self.layer_rope_theta(layer);
        let n_rot = self.layer_rope_n_rot(layer);

        // E4B (B): KV-shared layers reuse a donor layer's cached K/V. When
        // Some(d), this layer projects + RoPEs Q only, skips all K/V work,
        // and reads K/V from donor `d`'s cache slot. None ⇒ normal path.
        // The map is empty for non-E4B knots, so `kv_donor` is always None.
        let kv_donor: Option<usize> = self
            .e4b_kv_donor
            .get(layer)
            .copied()
            .flatten();
        let owns_kv = kv_donor.is_none();
        // Attention scale (ALL Gemma3/Gemma4 paths) = 1/sqrt(head_dim),
        // matching the golden reference EXACTLY.
        //
        // GOLDEN-DIFF FIX (2026-06-22): the prior `arch=="gemma4" → 1.0`
        // shortcut was WRONG and was the remaining gemma4-12b forward bug.
        // The working in-repo TS reference that produces "Paris"
        // (`open-source/aether/src/gcp-layer-node.ts:3148`) computes
        // `const scale = 1.0 / Math.sqrt(headDim)` for EVERY gemma layer —
        // sliding AND global — AND applies q_norm/k_norm on top (gcp-layer-
        // node.ts:3083-3105). The two are INDEPENDENT: q_norm/k_norm
        // renormalize each head to ~unit RMS × per-dim gain; they do NOT
        // supply the global 1/sqrt(head_dim) attention TEMPERATURE. With
        // `attn_scale = 1.0` the Q·Kᵀ scores ran ~head_dim/√head_dim ≈ 16×
        // too hot, the softmax over-saturated to near one-hot, and the
        // corrupted-but-bounded residual (g4final rms≈0.16, no balloon)
        // projected through the TIED unembed onto the highest-norm embedding
        // rows (236761/236772 of 262144) — the exact observed sane↔garbage
        // argmax OSCILLATION. HF dense Gemma3 scales by
        // `query_pre_attn_scalar**-0.5`, and for dense Gemma3-12B
        // `query_pre_attn_scalar == head_dim == 256`, so both conventions
        // coincide. We use `head_dim` directly (not the knot's
        // query_pre_attn_scalar metadata, which has been observed reporting
        // off-by values like 240/168) to match the Paris-producing aether
        // reference op-for-op. The earlier "CPU → Paris @ +16.3 with
        // scale=1.0" note did NOT reproduce on the current image
        // (MESH_GEMMA4_12B_HANDOFF.md): that salad was the mis-loaded gemma
        // tokenizer (since fixed); with correct input tokens, scale=1.0 is
        // the bug. The dense gemma4-labeled knot is architecturally Gemma3.
        // Attention temperature. DETERMINISTIC GROUND TRUTH (2026-06-22,
        // gemma4-paris-probe on the real gemma4-12b-it.knot with KNOWN-CORRECT
        // tokens, tokenizer bypassed): for dense gemma4 the working scale is
        // `1.0` (NOT 1/sqrt(head_dim)). gemma4's q_norm/k_norm use raw `w`
        // (no `(1+w)` shift), which already binds Q·K magnitudes — adding the
        // 1/sqrt(head_dim) temperature OVER-SQUASHES and decorrelates Q/K
        // (global pre-softmax scores collapse to ~0.1, attention goes uniform,
        // the tied unembed reads out high-frequency junk: argmax "▁and",
        // answer token at rank ~29000). With scale=1.0 + V-norm the probe puts
        // "▁Paris" as the top REAL-word token (behind only the structurally-
        // unused <unused94> special token, which production sampling masks).
        // The `GEMMA4_ATTN_SCALE` env overrides this for future bisection:
        //   one   → 1.0 (default for gemma4)
        //   hd    → 1/sqrt(head_dim)  (the regressed value)
        //   hd256 → 1/sqrt(256)
        //   qpas  → 1/sqrt(query_pre_attn_scalar)
        let attn_scale_default = if !self.e4b && cfg.arch == "gemma4" {
            1.0
        } else {
            match cfg.query_pre_attn_scalar {
                Some(s) if s > 0.0 => 1.0 / s.sqrt(),
                _ => 1.0 / (head_dim as f32).sqrt(),
            }
        };
        let attn_scale = match std::env::var("GEMMA4_ATTN_SCALE").ok().as_deref() {
            Some("qpas") => {
                let q = cfg.query_pre_attn_scalar.filter(|v| *v > 0.0).unwrap_or(head_dim as f32);
                1.0 / q.sqrt()
            }
            Some("hd256") => 1.0 / (256.0f32).sqrt(),
            Some("hd") => 1.0 / (head_dim as f32).sqrt(),
            Some("one") => 1.0,
            _ => attn_scale_default,
        };
        let sliding_window = if self.is_global_layer(layer) {
            None
        } else {
            cfg.sliding_window
        };

        // 1. attn_norm — RMSNorm of the residual stream into batch_xb.
        let attn_norm_w = self
            .knot
            .backend
            .fetch_tensor(&lw.attn_norm.name)
            .map_err(|e| format!("fetch attn_norm: {:?}", e))?;
        let attn_norm_v = bytes_to_f32_slice(&attn_norm_w);
        for i in 0..seq_len {
            let x_i = &self.batch_x[i * hidden_dim..(i + 1) * hidden_dim];
            let xb_i = &mut self.batch_xb[i * hidden_dim..(i + 1) * hidden_dim];
            gemma_rms_norm(
                xb_i,
                x_i,
                &attn_norm_v,
                cfg.rms_norm_eps,
                gemma_shift,
            );
        }
        drop(attn_norm_w);

        // 2. Q / K / V matmuls (batched over `seq_len`).
        let q_w = self
            .knot
            .backend
            .fetch_tensor(&lw.q.name)
            .map_err(|e| format!("fetch q: {:?}", e))?;
        matvec_memo::cached_mat_vec(
            &mut self.memo,
            &mut self.batch_q,
            &self.batch_xb,
            &q_w,
            lw.q.qtype,
            qkv_dim,
            hidden_dim,
            seq_len,
            self.q_stride,
            layer,
            matvec_memo::OP_Q,
            mat_vec_dispatch_batch,
        );
        drop(q_w);
        // E4B (B): shared layers (kv_donor = Some) skip K/V projection
        // entirely and reuse the donor layer's cached K/V below. Non-shared
        // layers (and all non-E4B knots) take the full K/V path.
        if owns_kv {
            let k_w = self
                .knot
                .backend
                .fetch_tensor(&lw.k.name)
                .map_err(|e| format!("fetch k: {:?}", e))?;
            matvec_memo::cached_mat_vec(
                &mut self.memo,
                &mut self.batch_k,
                &self.batch_xb,
                &k_w,
                lw.k.qtype,
                kv_dim,
                hidden_dim,
                seq_len,
                self.kv_stride,
                layer,
                matvec_memo::OP_K,
                mat_vec_dispatch_batch,
            );
            drop(k_w);
            let v_w = self
                .knot
                .backend
                .fetch_tensor(&lw.v.name)
                .map_err(|e| format!("fetch v: {:?}", e))?;
            matvec_memo::cached_mat_vec(
                &mut self.memo,
                &mut self.batch_v,
                &self.batch_xb,
                &v_w,
                lw.v.qtype,
                kv_dim,
                hidden_dim,
                seq_len,
                self.kv_stride,
                layer,
                matvec_memo::OP_V,
                mat_vec_dispatch_batch,
            );
            drop(v_w);
        }

        // 3. Scale-free per-head RMSNorm on V (Gemma3n / E4B ONLY).
        //
        // CORRECTNESS FIX (2026-06-22): this V unit-RMS belongs to
        // Gemma3n (the nested E4B family), NOT to dense Gemma3/"gemma4".
        //
        // Reference taxonomy (HF transformers, verified via WebFetch):
        //   - `Gemma3Attention` (DENSE 1B/4B/12B/27B — `modeling_gemma3.py`
        //     L337-356) carries ONLY `q_norm` + `k_norm`; it applies
        //     `query_states = self.q_norm(...)` / `key_states = self.k_norm(...)`
        //     and uses V RAW. There is NO `v_norm` — V is never normalized.
        //   - `Gemma3nTextAttention` (`modeling_gemma3n.py`) is the only one
        //     with `self.v_norm = Gemma3nRMSNorm(..., with_scale=False)` →
        //     a weightless per-head unit-RMS, exactly this block.
        //
        // The gemma4-12b-it / -31b knots are DENSE Gemma3 that the knot
        // encoder relabels `arch="gemma4"` (because they carry
        // `layer_output_scale`); they are NOT Gemma3n. They ship no
        // `v_norm` tensor and must use V RAW. The working TS Aether
        // reference confirms this: `gcp-layer-node.ts` does
        // `const v = vRaw;` and applies NO V normalization at all (it only
        // norms Q/K when `qLayerNorm`/`kLayerNorm` are present). The prior
        // `cfg.arch == "gemma4"` gate force-normalized every V head to unit
        // RMS on dense Gemma3, destroying the learned V magnitude
        // distribution. Because the lm_head is the TIED token-embedding
        // matrix, the corrupted readout collapses onto the highest-norm
        // embedding rows (single-char SentencePiece pieces in the
        // high-vocab tail, ids ~236xxx of 262144) — the exact
        // high-vocab-argmax garbage observed on CPU == f16-GPU == f32-GPU.
        //
        // Gate on `self.e4b` (Gemma3n presence, detected from the PLE
        // embedding table) so only genuine Gemma3n applies it.
        // E4B (B): skip on shared layers — V was never projected here; the
        // donor already v_norm'd its own cached V.
        // V-norm (per-head scale-free unit RMS on V). DETERMINISTIC GROUND
        // TRUTH (2026-06-22, gemma4-paris-probe): dense gemma4 needs V-norm ON
        // (the Jun-19 Paris-producing binary gated it on `arch=="gemma4"`).
        // The session that disabled it (gating only on `self.e4b`) regressed
        // the readout. Default = ON for e4b OR dense gemma4. `GEMMA4_VNORM`
        // env overrides (1=on, 0=off) for bisection.
        let vnorm_on = match std::env::var("GEMMA4_VNORM").ok().as_deref() {
            Some("1") => true,
            Some("0") => false,
            _ => self.e4b || cfg.arch == "gemma4",
        };
        if vnorm_on && owns_kv {
            for i in 0..seq_len {
                let v_i = &mut self.batch_v[i * self.kv_stride..i * self.kv_stride + kv_dim];
                for h in 0..n_kv {
                    let head = &mut v_i[h * head_dim..(h + 1) * head_dim];
                    let mut sum_sq = 0.0f32;
                    for &x in head.iter() {
                        sum_sq += x * x;
                    }
                    let inv = 1.0 / (sum_sq / head_dim as f32 + cfg.rms_norm_eps).sqrt();
                    for x in head.iter_mut() {
                        *x *= inv;
                    }
                }
            }
        }

        // 4. Per-head Q/K RMSNorm (Gemma3/4 only). The weight is shared
        //    across heads inside one layer.
        //
        // GAMMA CONVENTION: gemma3 q_norm/k_norm are `Gemma3RMSNorm` →
        // `out = x * inv * (1 + w)` (HF stores the gamma as a delta from
        // identity). gemma4 stores already-shifted weights → raw `w`. The
        // working TS Aether reference passes `gemmaGammaShift = isGemma3` to
        // its per-head rmsNorm for BOTH q_norm and k_norm
        // (`gcp-layer-node.ts:3478-3504`). Earlier this called the raw
        // `rms_norm_per_head` unconditionally, dropping the `(1+w)` for
        // gemma3 — Q·K^T scores were computed against un-shifted Q/K →
        // garbage argmax. Dispatch on arch like every other gemma norm.
        let qk_shift = gemma_shift;
        if let Some(qn) = lw.q_norm.as_ref() {
            let qn_bytes = self
                .knot
                .backend
                .fetch_tensor(&qn.name)
                .map_err(|e| format!("fetch q_norm: {:?}", e))?;
            let qn_v = bytes_to_f32_slice(&qn_bytes);
            for i in 0..seq_len {
                let q_i = &mut self.batch_q[i * self.q_stride..i * self.q_stride + qkv_dim];
                if qk_shift {
                    rms_norm_per_head_shifted(
                        q_i,
                        &qn_v,
                        cfg.num_heads,
                        head_dim,
                        cfg.rms_norm_eps,
                    );
                } else {
                    rms_norm_per_head(q_i, &qn_v, cfg.num_heads, head_dim, cfg.rms_norm_eps);
                }
            }
            drop(qn_bytes);
        }
        // K-norm only runs when this layer owns its K (E4B shared layers
        // reuse the donor's already-normed cached K).
        if owns_kv {
            if let Some(kn) = lw.k_norm.as_ref() {
                let kn_bytes = self
                    .knot
                    .backend
                    .fetch_tensor(&kn.name)
                    .map_err(|e| format!("fetch k_norm: {:?}", e))?;
                let kn_v = bytes_to_f32_slice(&kn_bytes);
                for i in 0..seq_len {
                    let k_i = &mut self.batch_k[i * self.kv_stride..i * self.kv_stride + kv_dim];
                    if qk_shift {
                        rms_norm_per_head_shifted(k_i, &kn_v, n_kv, head_dim, cfg.rms_norm_eps);
                    } else {
                        rms_norm_per_head(k_i, &kn_v, n_kv, head_dim, cfg.rms_norm_eps);
                    }
                }
                drop(kn_bytes);
            }
        }

        // 4. RoPE (partial when configured). Apply per token at its
        //    absolute position `start_pos + i`.
        //
        // Wave-22 split-a Fix C: prefer the precomputed cos/sin table
        // when its (head_dim, theta) shape matches this layer. Tables
        // are bounded by KV_MAX_SEQ_LEN; positions beyond fall back to
        // the per-call trig path. Sliding layers pull from
        // `rope_table_local` (head_dim/theta = local), global layers
        // from `rope_table_global` (global_head_dim/theta = rope_theta).
        let is_global = self.is_global_layer(layer);
        let table: Option<&[f32]> = if is_global {
            if head_dim == self.rope_table_global_head_dim {
                Some(self.rope_table_global.as_slice())
            } else {
                None
            }
        } else {
            self.rope_table_local.as_ref().and_then(|t| {
                if head_dim == self.rope_table_local_head_dim {
                    Some(t.as_slice())
                } else {
                    None
                }
            })
        };
        // RoPE rotates Q (always) and K (only when this layer owns its K).
        // For E4B shared layers we still must rotate Q at the absolute pos,
        // so we rotate against a throwaway K scratch buffer (the donor's
        // cached K is already roped and reused unchanged below).
        let mut k_scratch = vec![0f32; if owns_kv { 0 } else { kv_dim }];
        // Gemma3/Gemma4 GLOBAL-layer linear RoPE position scaling: the
        // non-cached fallback (positions past the precomputed table) must
        // divide the position by `ropeScalingFactor` (default 8.0) on
        // global layers, matching `applyRoPE(scaledPosition = position /
        // ropeScalingFactor)` in the Aether reference. Sliding/local layers
        // use no scaling. The cached fast path already bakes this into
        // `rope_table_global` (see `precompute_rope_table_scaled` above).
        let inv_pos_scale = if is_global {
            1.0 / cfg.rope_scaling_factor.filter(|f| *f > 0.0).unwrap_or(1.0)
        } else {
            1.0
        };
        for i in 0..seq_len {
            let pos = start_pos + i;
            let pos_f = pos as f32 * inv_pos_scale;
            // Split batch_q borrow from batch_k borrow safely.
            let q_i = &mut self.batch_q[i * self.q_stride..i * self.q_stride + qkv_dim];
            // Cached path requires `pos + 1` rows in the table.
            let use_cached = match table {
                Some(t) => (pos + 1) * head_dim <= t.len(),
                None => false,
            };
            if owns_kv {
                let k_i = &mut self.batch_k[i * self.kv_stride..i * self.kv_stride + kv_dim];
                if use_cached {
                    let t = table.expect("table is Some when use_cached");
                    if n_rot == head_dim {
                        rope_neox_cached(q_i, k_i, pos, cfg.num_heads, n_kv, head_dim, t);
                    } else {
                        rope_neox_partial_cached(
                            q_i, k_i, pos, cfg.num_heads, n_kv, head_dim, n_rot, t,
                        );
                    }
                } else if n_rot == head_dim {
                    rope_neox_f(q_i, k_i, pos_f, cfg.num_heads, n_kv, head_dim, theta);
                } else {
                    rope_neox_partial_f(
                        q_i, k_i, pos_f, cfg.num_heads, n_kv, head_dim, n_rot, theta,
                    );
                }
            } else {
                // Q-only rotation (shared layer). k_scratch is discarded.
                let k_i = &mut k_scratch[..];
                if use_cached {
                    let t = table.expect("table is Some when use_cached");
                    if n_rot == head_dim {
                        rope_neox_cached(q_i, k_i, pos, cfg.num_heads, n_kv, head_dim, t);
                    } else {
                        rope_neox_partial_cached(
                            q_i, k_i, pos, cfg.num_heads, n_kv, head_dim, n_rot, t,
                        );
                    }
                } else if n_rot == head_dim {
                    rope_neox_f(q_i, k_i, pos_f, cfg.num_heads, n_kv, head_dim, theta);
                } else {
                    rope_neox_partial_f(
                        q_i, k_i, pos_f, cfg.num_heads, n_kv, head_dim, n_rot, theta,
                    );
                }
            }
        }

        // 5. KV cache save (per token). save_kv expects a flat
        //    (n_kv_heads × head_dim) vector matching the cache's layout.
        //    We pad sliding-layer heads (256) into the cache slots (512).
        //    E4B (B): shared layers cache nothing — they read the donor's
        //    slot in the attention compute below.
        let cache_hd = self.kv_cache.head_dim;
        if owns_kv {
            let mut k_buf = vec![0f32; self.kv_cache.num_kv_heads * cache_hd];
            let mut v_buf = vec![0f32; self.kv_cache.num_kv_heads * cache_hd];
            for i in 0..seq_len {
                let pos = start_pos + i;
                for h in 0..n_kv {
                    let src_off = i * self.kv_stride + h * head_dim;
                    let dst_off = h * cache_hd;
                    k_buf[dst_off..dst_off + head_dim]
                        .copy_from_slice(&self.batch_k[src_off..src_off + head_dim]);
                    v_buf[dst_off..dst_off + head_dim]
                        .copy_from_slice(&self.batch_v[src_off..src_off + head_dim]);
                }
                self.kv_cache.save_kv(layer, pos, &k_buf, &v_buf);
            }
        }

        // GEMMA4_DBG: post-projection Q/K/V health (after Q/K/V matmuls — which
        // take the f16 CUDA GEMM under FLUX_GPU_WEIGHT_DTYPE=f16 — plus v_norm,
        // q_norm/k_norm, and RoPE). For global layers Q/K are head_dim=512 wide;
        // an f16-overflowed projection shows up here as a large `qmax`/`kmax` or
        // a nonzero nan/inf BEFORE the score dot products.
        #[cfg(not(target_arch = "wasm32"))]
        if gemma4_dbg() {
            let q_used = seq_len * self.q_stride;
            let kv_used = seq_len * self.kv_stride;
            let (qmax, qnan, qinf) = g4_stats(&self.batch_q[..q_used.min(self.batch_q.len())]);
            let (kmax, knan, kinf) = g4_stats(&self.batch_k[..kv_used.min(self.batch_k.len())]);
            let (vmax, vnan, vinf) = g4_stats(&self.batch_v[..kv_used.min(self.batch_v.len())]);
            eprintln!(
                "[g4dbg] layer={layer} global={is_global} f16cuda={used_f16_cuda} \
                 post-QKV q[max={qmax:.4e} nan={qnan} inf={qinf}] \
                 k[max={kmax:.4e} nan={knan} inf={kinf}] \
                 v[max={vmax:.4e} nan={vnan} inf={vinf}]"
            );
        }

        // 6. Attention compute → batch_xb (overwriting the post-attn-norm
        //    we wrote earlier; we no longer need that copy).
        // E4B (B): shared layers read K/V from their donor's cache slot.
        let kv_layer = kv_donor.unwrap_or(layer);
        let layer_offset = self.kv_cache.get_key_layer_offset(kv_layer);
        let max_seq_len = self.kv_cache.max_seq_len;
        let num_kv_groups = cfg.num_heads / n_kv;
        for i in 0..seq_len {
            let pos = start_pos + i;
            let attn_window_start = match sliding_window {
                Some(w) => pos.saturating_sub(w.saturating_sub(1)),
                None => 0,
            };

            for h in 0..cfg.num_heads {
                let kv_h = h / num_kv_groups;
                let kv_head_offset = layer_offset + kv_h * max_seq_len * cache_hd;

                let mut head_att = [0.0f32; 4096]; // covers max_seq_len up to 4096
                let att_len = pos + 1;
                let att_slice = &mut head_att[..att_len];

                let q_off = i * self.q_stride + h * head_dim;
                let q_head = &self.batch_q[q_off..q_off + head_dim];

                // K[0..=pos] for this kv_head, in cache layout.
                // We use a loop for dot products to handle the padding/stride in the cache.
                for t in 0..att_len {
                    let k_off = kv_head_offset + t * cache_hd;
                    let k_t = unsafe {
                        let ptr = self.kv_cache.keys.as_ptr().add(k_off);
                        std::slice::from_raw_parts(ptr, head_dim)
                    };
                    let score = dot_product(q_head, k_t) * attn_scale;
                    att_slice[t] = if t < attn_window_start {
                        f32::NEG_INFINITY
                    } else {
                        score
                    };
                }
                // GEMMA4_DBG: log the pre-softcap/pre-softmax attention-score
                // max|abs| for the FIRST global layer (head 0, last query). The
                // global path (head_dim 512, attn_scale=1/sqrt(head_dim), partial-RoPE) is the
                // leading f16-overflow suspect — if Q·Kᵀ here is already huge or
                // non-finite the divergence is in the global attention math, not
                // downstream. Gated + first-global-layer-only ⇒ negligible cost.
                #[cfg(not(target_arch = "wasm32"))]
                if gemma4_dbg()
                    && is_global
                    && layer == cfg.sliding_window_pattern.map(|p| p.saturating_sub(1)).unwrap_or(0)
                    && h == 0
                    && i == seq_len - 1
                {
                    let (smax, snan, sinf) = g4_stats(att_slice);
                    eprintln!(
                        "[g4dbg] layer={layer} GLOBAL attn-score(pre-softmax) head=0 \
                         att_len={att_len} max={smax:.4e} nan={snan} inf={sinf} \
                         attn_scale={attn_scale} head_dim={head_dim} n_rot={n_rot}"
                    );
                }
                softmax(att_slice);

                // Weighted sum of V[0..=pos] → write into batch_xb at the
                // (i, h) head slot.
                let xb_off = i * qkv_dim + h * head_dim;
                let xb_head = &mut self.batch_xb[xb_off..xb_off + head_dim];
                for j in 0..head_dim {
                    xb_head[j] = 0.0;
                }
                let values_ptr = self.kv_cache.values.as_ptr();
                for t in 0..att_len {
                    if !att_slice[t].is_finite() {
                        continue;
                    }
                    let v_off = kv_head_offset + t * cache_hd;
                    let v_slice_t =
                        unsafe { std::slice::from_raw_parts(values_ptr.add(v_off), head_dim) };
                    accumulate_weighted(xb_head, v_slice_t, att_slice[t]);
                }
            }
        }

        // 7. O matmul: batch_xb (attn output, head-major qkv_dim per token)
        //    → batch_xb2 (hidden_dim per token).
        let o_w = self
            .knot
            .backend
            .fetch_tensor(&lw.o.name)
            .map_err(|e| format!("fetch o: {:?}", e))?;
        matvec_memo::cached_mat_vec(
            &mut self.memo,
            &mut self.batch_xb2,
            &self.batch_xb,
            &o_w,
            lw.o.qtype,
            hidden_dim,
            qkv_dim,
            seq_len,
            hidden_dim,
            layer,
            matvec_memo::OP_O,
            mat_vec_dispatch_batch,
        );
        drop(o_w);

        // 8. post-attention sandwich norm, applied to the O-projection output
        //    BEFORE the residual add. Gemma3's admitted GGUF path uses
        //    ffn_norm here; Gemma4's HF/Aether path uses post_attention_norm
        //    here and reserves ffn_norm for the MLP pre-norm below.
        if lw.post_attn_norm.is_some() {
            let post_attn_ref = if cfg.arch == "gemma4" {
                lw.post_attn_norm.as_ref().unwrap()
            } else {
                &lw.ffn_norm
            };
            let pn_bytes = self
                .knot
                .backend
                .fetch_tensor(&post_attn_ref.name)
                .map_err(|e| format!("fetch post-attn norm: {:?}", e))?;
            let pn_v = bytes_to_f32_slice(&pn_bytes);
            // RMSNorm the O output in batch_xb2 in-place (per token) — but
            // rms_norm reads x then writes out, so use batch_xb as scratch.
            for i in 0..seq_len {
                let xb2_in = &self.batch_xb2[i * hidden_dim..(i + 1) * hidden_dim].to_vec();
                let xb2_out = &mut self.batch_xb2[i * hidden_dim..(i + 1) * hidden_dim];
                gemma_rms_norm(
                    xb2_out,
                    xb2_in,
                    &pn_v,
                    cfg.rms_norm_eps,
                    gemma_shift,
                );
            }
            drop(pn_bytes);
        }

        // 9. Residual add: batch_x[i] += batch_xb2[i]. Then apply the MLP
        //    pre-norm into batch_xb so the next phase consumes it directly.
        //    Gemma3's admitted path uses post_attention_norm here; Gemma4
        //    uses ffn_norm here to match the Aether Gemma4 path.
        let pre_ffn_name = if cfg.arch == "gemma4" {
            lw.ffn_norm.name.as_str()
        } else {
            lw.post_attn_norm
                .as_ref()
                .map(|t| t.name.as_str())
                .unwrap_or(lw.ffn_norm.name.as_str())
        };
        let ffn_norm_w = self
            .knot
            .backend
            .fetch_tensor(pre_ffn_name)
            .map_err(|e| format!("fetch pre-ffn norm: {:?}", e))?;
        let ffn_norm_v = bytes_to_f32_slice(&ffn_norm_w);
        for i in 0..seq_len {
            let x_i = &mut self.batch_x[i * hidden_dim..(i + 1) * hidden_dim];
            let xb2_i = &self.batch_xb2[i * hidden_dim..(i + 1) * hidden_dim];
            for j in 0..hidden_dim {
                x_i[j] += xb2_i[j];
            }
            let xb_i = &mut self.batch_xb[i * hidden_dim..(i + 1) * hidden_dim];
            gemma_rms_norm(
                xb_i,
                x_i,
                &ffn_norm_v,
                cfg.rms_norm_eps,
                gemma_shift,
            );
        }
        drop(ffn_norm_w);

        // GEMMA4_DBG: post-attention residual health. batch_x now holds the
        // residual stream AFTER (O-proj + post_attn_norm + residual add). This
        // is the first point a blown-up attention output (e.g. an f16-overflowed
        // O-proj on a global layer) shows in the residual stream itself.
        #[cfg(not(target_arch = "wasm32"))]
        if gemma4_dbg() {
            let used = seq_len * hidden_dim;
            let (rmax, rnan, rinf) = g4_stats(&self.batch_x[..used.min(self.batch_x.len())]);
            eprintln!(
                "[g4dbg] layer={layer} global={is_global} post-attn residual \
                 max={rmax:.4e} nan={rnan} inf={rinf}"
            );
        }

        Ok(())
    }

    /// Split phase 2a: gate matmul.
    pub fn forward_range_ffn_gate_chunk(&mut self, layer: usize, seq_len: usize) -> Result<()> {
        // Gate-up role grows {xb, hb, hb2}. Skip q/k/v/logits.
        self.ensure_xb_seq(seq_len);
        self.ensure_hb_seq(seq_len);
        let cfg = &self.config;
        let lw = &self.locs.layers[layer];
        let gate_w = self
            .knot
            .backend
            .fetch_tensor(&lw.gate.name)
            .map_err(|e| format!("fetch gate: {:?}", e))?;
        matvec_memo::cached_mat_vec(
            &mut self.memo,
            &mut self.batch_hb,
            &self.batch_xb,
            &gate_w,
            lw.gate.qtype,
            cfg.intermediate_size,
            cfg.hidden_dim,
            seq_len,
            cfg.intermediate_size,
            layer,
            matvec_memo::OP_FFN_GATE,
            mat_vec_dispatch_batch,
        );
        Ok(())
    }

    /// Split phase 2b: up matmul + GeGLU activation. Gemma uses
    /// `gelu(gate) * up` (NOT swiglu's silu). The fused write goes to
    /// batch_hb so the down matmul can consume it.
    pub fn forward_range_ffn_up_chunk(&mut self, layer: usize, seq_len: usize) -> Result<()> {
        // Up-projection writes batch_hb2 then fuses into batch_hb.
        self.ensure_xb_seq(seq_len);
        self.ensure_hb_seq(seq_len);
        self.ensure_hb2_seq(seq_len);
        let cfg = &self.config;
        let lw = &self.locs.layers[layer];
        let up_w = self
            .knot
            .backend
            .fetch_tensor(&lw.up.name)
            .map_err(|e| format!("fetch up: {:?}", e))?;
        matvec_memo::cached_mat_vec(
            &mut self.memo,
            &mut self.batch_hb2,
            &self.batch_xb,
            &up_w,
            lw.up.qtype,
            cfg.intermediate_size,
            cfg.hidden_dim,
            seq_len,
            cfg.intermediate_size,
            layer,
            matvec_memo::OP_FFN_UP,
            mat_vec_dispatch_batch,
        );
        drop(up_w);
        for i in 0..seq_len {
            let hb_i =
                &mut self.batch_hb[i * cfg.intermediate_size..(i + 1) * cfg.intermediate_size];
            let hb2_i = &self.batch_hb2[i * cfg.intermediate_size..(i + 1) * cfg.intermediate_size];
            gelu_glu_inplace(hb_i, hb2_i);
        }
        Ok(())
    }

    /// Wave-23 Bug B Path E (combined split-b export). Fuses `set_batch_xb +
    /// forward_range_ffn_gate_chunk + forward_range_ffn_up_chunk +
    /// get_batch_hb_residual` into ONE wasm-bindgen export call so the JS
    /// caller never holds a Float32Array view across an intervening
    /// `memory.grow`.
    ///
    /// **Why a single boundary call matters**: Paths A-D failed because
    /// `memory.grow` could fire BETWEEN consecutive wasm-bindgen exports
    /// (`set_batch_xb` → `forward_*` → `get_batch_hb*`). Each export is its
    /// own JS frame; wasm-bindgen's typed-array view cache (or even the
    /// fresh-construct Path D) crosses three frames and can race the V8
    /// growable-buffer machinery. With Path E, all allocations happen
    /// inside ONE synchronous wasm execution, the heap reaches its
    /// high-water mark by the time we serialize the return value, and the
    /// final `__wbindgen_malloc` for the export-staging buffer is the
    /// LAST allocation of the call frame — no further grow can race the
    /// JS-side `getArrayF32FromWasm0` read.
    ///
    /// Returns `batch_hb[..seq_len * intermediate_size]` as `Vec<f32>`.
    /// Caller-visible behaviour is identical to the old three-call sequence.
    pub fn split_b_chunk(
        &mut self,
        batch_xb: &[f32],
        layer: usize,
        seq_len: usize,
    ) -> Result<Vec<f32>> {
        // Stage input into batch_xb (mirrors set_batch_xb_residual).
        let hidden_dim = self.config.hidden_dim.max(1);
        let derived_seq = batch_xb.len() / hidden_dim;
        let stage_seq = derived_seq.max(seq_len);
        self.ensure_xb_seq(stage_seq);
        if batch_xb.len() > self.batch_xb.len() {
            return Err(format!(
                "split_b_chunk: input len {} > batch_xb cap {}",
                batch_xb.len(),
                self.batch_xb.len()
            ));
        }
        self.batch_xb[..batch_xb.len()].copy_from_slice(batch_xb);

        // Grow remaining FFN scratch buffers up front so the per-call
        // matmul branches do not trigger fresh grows.
        self.ensure_hb_seq(seq_len);
        self.ensure_hb2_seq(seq_len);

        // Run gate then up (which fuses GeGLU into batch_hb).
        self.forward_range_ffn_gate_chunk(layer, seq_len)?;
        self.forward_range_ffn_up_chunk(layer, seq_len)?;

        // Materialise the result. `get_batch_hb_residual` already handles
        // the "buffer wasn't grown" zero-fill fallback.
        Ok(self.get_batch_hb_residual(seq_len))
    }

    /// Split phase 3: down matmul + post_ffw_norm + layer_output_scale +
    /// residual add. Returns the post-MLP residual when `is_last_layer=true`.
    pub fn forward_range_ffn_down_chunk(
        &mut self,
        layer: usize,
        seq_len: usize,
        is_last_layer: bool,
    ) -> Result<Vec<f32>> {
        let gemma_shift = self.gemma_norm_shift();
        // Down role grows {x, xb2, hb}. xb is consumed read-only above.
        self.ensure_x_seq(seq_len);
        self.ensure_xb2_seq(seq_len);
        self.ensure_hb_seq(seq_len);
        let cfg = &self.config;
        let hidden_dim = cfg.hidden_dim;
        let lw = &self.locs.layers[layer];

        // 1. Down matmul: batch_hb (intermediate) → batch_xb2 (hidden_dim).
        let down_w = self
            .knot
            .backend
            .fetch_tensor(&lw.down.name)
            .map_err(|e| format!("fetch down: {:?}", e))?;
        matvec_memo::cached_mat_vec(
            &mut self.memo,
            &mut self.batch_xb2,
            &self.batch_hb,
            &down_w,
            lw.down.qtype,
            hidden_dim,
            cfg.intermediate_size,
            seq_len,
            hidden_dim,
            layer,
            matvec_memo::OP_FFN_DOWN,
            mat_vec_dispatch_batch,
        );
        drop(down_w);

        // 2. post_ffw_norm scaling (Gemma3/4 only) — applied to the down
        //    output BEFORE the residual add.
        if let Some(pn) = lw.post_ffw_norm.as_ref() {
            let pn_bytes = self
                .knot
                .backend
                .fetch_tensor(&pn.name)
                .map_err(|e| format!("fetch post_ffw_norm: {:?}", e))?;
            let pn_v = bytes_to_f32_slice(&pn_bytes);
            for i in 0..seq_len {
                let xb2_in = &self.batch_xb2[i * hidden_dim..(i + 1) * hidden_dim].to_vec();
                let xb2_out = &mut self.batch_xb2[i * hidden_dim..(i + 1) * hidden_dim];
                gemma_rms_norm(
                    xb2_out,
                    xb2_in,
                    &pn_v,
                    cfg.rms_norm_eps,
                    gemma_shift,
                );
            }
            drop(pn_bytes);
        }

        // 3. Residual add: batch_x[i] += batch_xb2[i].
        for i in 0..seq_len {
            let x_i = &mut self.batch_x[i * hidden_dim..(i + 1) * hidden_dim];
            let xb2_i = &self.batch_xb2[i * hidden_dim..(i + 1) * hidden_dim];
            for j in 0..hidden_dim {
                x_i[j] += xb2_i[j];
            }
        }

        // 4. layer_output_scale (Gemma4-labeled knots only) — a single per-layer
        // F32 scalar carried by the GGUF as `blk.<L>.layer_output_scale.weight`.
        //
        // DEFAULT: NOT APPLIED. The gemma4-12b/-31b knots are DENSE Gemma3 that
        // the knot encoder relabels `arch="gemma4"` SOLELY because they carry
        // this tensor (`bitwise/scripts/encode-llama-knot.ts:433-438`). The
        // working in-repo TS reference that produces "Paris"
        // (`open-source/aether/src/gcp-layer-node.ts`) registers gemma4-12b as
        // `architecture: 'gemma3'` and ends every layer at
        // `output[i] = afterAttn[i] + mlpOutput[i]` — there is NO per-layer
        // output scalar anywhere in it. HF dense Gemma3
        // (`Gemma3DecoderLayer.forward`) likewise has no post-layer residual
        // scale. Multiplying the residual by this scalar (~0.04–0.99, mean ≈ 0.6)
        // on every layer was the root cause of the INVARIANT high-vocab-argmax
        // garbage (lm_head → 236xxx of 262144): it corrupts the final hidden
        // state, and because lm_head is the TIED token-embedding the corrupted
        // readout collapses onto the highest-norm embedding rows. The bug was
        // invariant to f16-GPU / f32-act GPU / pure-CPU exact-f64 / V-norm
        // removal precisely because this scale sits on the always-applied
        // per-layer path none of those interventions touched.
        //
        // Set `GEMMA4_APPLY_LAYER_OUTPUT_SCALE=1` to re-enable for A/B.
        // The tensor is always READ for diagnostics (under GEMMA4_DBG) so a
        // single deploy can confirm its presence/value/where without a rebuild.
        if let Some(scale_ref) = lw.layer_output_scale.as_ref() {
            let scale_bytes = self
                .knot
                .backend
                .fetch_tensor(&scale_ref.name)
                .map_err(|e| format!("fetch layer_output_scale: {:?}", e))?;
            let scale_v = bytes_to_f32_slice(&scale_bytes);
            if scale_v.is_empty() {
                return Err(format!("layer_output_scale len 0 (layer {})", layer));
            }
            let s = scale_v[0];
            let apply = gemma4_apply_layer_output_scale();
            // GEMMA4_DBG: surface the per-layer scalar, its first few values, and
            // whether it is actually being applied. With the default (apply=false)
            // the residual is left UNSCALED — matching the Paris-producing TS ref.
            #[cfg(not(target_arch = "wasm32"))]
            if gemma4_dbg() {
                let head: Vec<String> = scale_v
                    .iter()
                    .take(4)
                    .map(|v| format!("{v:.6e}"))
                    .collect();
                eprintln!(
                    "[g4scale] layer={layer} global={} present=true applied={apply} \
                     s={s:.6e} first4=[{}] len={} (multiplies FULL residual after MLP add)",
                    self.is_global_layer(layer),
                    head.join(", "),
                    scale_v.len()
                );
            }
            if apply {
                for i in 0..seq_len {
                    let x_i = &mut self.batch_x[i * hidden_dim..(i + 1) * hidden_dim];
                    scalar_mul(x_i, s);
                }
            }
            drop(scale_bytes);
        } else {
            #[cfg(not(target_arch = "wasm32"))]
            if gemma4_dbg() {
                eprintln!("[g4scale] layer={layer} present=false");
            }
        }

        // GEMMA4_DBG>=2: per-layer last-token residual VALUE dump (first 8
        // elements) — diff vs the HF ground-truth L00-L48 to localize the GPU
        // f16 divergence (gradual precision drift vs a sharp single-layer bug).
        #[cfg(not(target_arch = "wasm32"))]
        if gemma4_dbg_level() >= 2 {
            let base = (seq_len - 1) * hidden_dim;
            let v = &self.batch_x[base..base + 8.min(hidden_dim)];
            let s = v
                .iter()
                .map(|x| format!("{x:+.4}"))
                .collect::<Vec<_>>()
                .join(" ");
            eprintln!("[g4val] layer={layer} last-tok[:8]= {s}");
        }

        if is_last_layer {
            let mut out = vec![0.0f32; seq_len * hidden_dim];
            out.copy_from_slice(&self.batch_x[..seq_len * hidden_dim]);
            Ok(out)
        } else {
            Ok(vec![])
        }
    }

    /// Apply final RMSNorm + lm_head matmul + tanh logit softcap.
    /// Returns logits for the LAST token in the chunk.
    pub fn lm_head_only(&mut self, input: &[f32], seq_len: usize) -> Result<Vec<f32>> {
        let gemma_shift = self.gemma_norm_shift();
        let hidden_dim = self.config.hidden_dim;
        let vocab_size = self.config.vocab_size;
        if input.len() != seq_len * hidden_dim {
            return Err(format!(
                "lm_head_only: input len {} != seq_len({}) * hidden_dim({})",
                input.len(),
                seq_len,
                hidden_dim
            ));
        }
        // Lazy-allocate the buffers lm-head touches. Trisplit a/g/d
        // workers never reach this path, so they avoid the 8 MiB heap
        // pressure of pre-allocating `BATCH_CAPACITY * vocab_size` and
        // also skip the smaller batch_x / batch_xb scratch.
        self.ensure_x();
        self.ensure_xb();
        let needed = BATCH_CAPACITY * vocab_size;
        if self.batch_logits.len() < needed {
            self.batch_logits.resize(needed, 0.0);
        }
        let cfg = &self.config;
        self.batch_x[..seq_len * hidden_dim].copy_from_slice(input);

        // Final RMSNorm (output_norm.weight) into batch_xb.
        let final_norm_w = self
            .knot
            .backend
            .fetch_tensor(&self.locs.final_norm.name)
            .map_err(|e| format!("fetch final_norm: {:?}", e))?;
        let final_norm_v = bytes_to_f32_slice(&final_norm_w);

        // GEMMA4_DBG: final-hidden RMS/max BEFORE the final norm, for the LAST
        // token. The residual is reported to balloon to ~2.7e2 mid-network; this
        // shows what the final norm receives. final_norm shift_by_one is gated on
        // `arch=="gemma3"` → FALSE for the gemma4-labeled knot = RAW weight,
        // matching the Paris-producing TS ref (`rmsNorm: (x/rms)*weight[i]`, no
        // `(1+w)` shift).
        #[cfg(not(target_arch = "wasm32"))]
        if gemma4_dbg() {
            let base = (seq_len - 1) * hidden_dim;
            let (rms, mx) = g4_rms_max(&self.batch_x[base..base + hidden_dim]);
            let (wrms, wmx) = g4_rms_max(&final_norm_v[..hidden_dim.min(final_norm_v.len())]);
            eprintln!(
                "[g4final] PRE-norm last-tok rms={rms:.4} max={mx:.4} | \
                 final_norm shift_by_one={} (arch={}) gain_rms={wrms:.4} gain_max={wmx:.4}",
                gemma_shift,
                cfg.arch
            );
        }

        for i in 0..seq_len {
            let x_i = &self.batch_x[i * hidden_dim..(i + 1) * hidden_dim];
            let xb_i = &mut self.batch_xb[i * hidden_dim..(i + 1) * hidden_dim];
            gemma_rms_norm(
                xb_i,
                x_i,
                &final_norm_v,
                cfg.rms_norm_eps,
                gemma_shift,
            );
        }
        drop(final_norm_w);

        // GEMMA4_DBG: final-hidden RMS/max AFTER the final norm, for the LAST
        // token. A healthy gemma final-hidden post-norm RMS is O(1); a value
        // that tracks the gain RMS but still feeds garbage logits would point at
        // the lm_head readout / embed-tie orientation rather than the norm.
        #[cfg(not(target_arch = "wasm32"))]
        if gemma4_dbg() {
            let base = (seq_len - 1) * hidden_dim;
            let (rms, mx) = g4_rms_max(&self.batch_xb[base..base + hidden_dim]);
            eprintln!("[g4final] POST-norm last-tok rms={rms:.4} max={mx:.4}");
        }

        // LM head matmul. Gemma3/4 use TIED embeddings — `lm_head` resolves
        // to `token_embd_weight` via resolve_all's fallback.
        //
        // F-mesh-3 fix: when GNOSIS_LM_HEAD_FP32=1, route through a one-
        // time pre-dequantized FP32 cache (matches Aether v197-napi). The
        // on-the-fly quantized dispatch (else branch) is the trisplit/legacy
        // path — see `lm_head_fp32` field doc for the full rationale and
        // memory tradeoff.
        let lm_head_fp32_enabled = std::env::var("GNOSIS_LM_HEAD_FP32")
            .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
            .unwrap_or(false);

        if lm_head_fp32_enabled && self.lm_head_fp32.is_none() {
            // Lazy alloc: 5.6 GiB for gemma4-31b. We use the same per-qtype
            // dequant arithmetic that the quantized matvec dispatch calls
            // internally — bit-exact equivalent dequant, just front-loaded
            // once instead of once per forward pass.
            let lm_w = self
                .knot
                .backend
                .fetch_tensor(&self.locs.lm_head.name)
                .map_err(|e| format!("fetch lm_head (fp32 prefetch): {:?}", e))?;
            let lm_bytes: &[u8] = &lm_w;
            let lm_qtype = self.locs.lm_head.qtype;
            let n_elem = cfg.vocab_size * hidden_dim;
            let mut fp32 = vec![0f32; n_elem];
            // Dispatch on the REAL lm_head quant type. The tied lm_head is
            // `token_embd`, which K-quants (Q4_K_M etc.) store at a HIGHER
            // precision than the body — ggml-org's gemma-4-12B-it Q4_K_M keeps
            // token_embd at Q6_K. Hardcoding `dequantize_q4k_row` here misread
            // those Q6_K bytes → ~46% NaN logits (gemma4-12b-it gate, 2026-06-08).
            // Mirror the qtype dispatch the embedding lookup + legacy path use.
            for row in 0..cfg.vocab_size {
                let dst = &mut fp32[row * hidden_dim..(row + 1) * hidden_dim];
                match lm_qtype {
                    QType::F32 => {
                        let s = row * hidden_dim * 4;
                        let f = bytes_to_f32_slice(&lm_bytes[s..s + hidden_dim * 4]);
                        dst.copy_from_slice(&f[..hidden_dim]);
                    }
                    QType::F16 => dequantize_f16_row(dst, lm_bytes, row, hidden_dim),
                    QType::IQ2S => crate::iq_dequant::dequantize_iq2s_row(dst, lm_bytes, row, hidden_dim),
                    QType::IQ3S => crate::iq_dequant::dequantize_iq3s_row(dst, lm_bytes, row, hidden_dim),
                    QType::KAIJU1 => crate::kaiju_format::dequantize_kaiju1_row(dst, lm_bytes, row, hidden_dim),
                    QType::Q4K => dequantize_q4k_row(dst, lm_bytes, row, hidden_dim),
                    QType::Q5_0 => dequantize_q5_0_row(dst, lm_bytes, row, hidden_dim),
                    QType::Q5K => dequantize_q5k_row(dst, lm_bytes, row, hidden_dim),
                    QType::Q6K => dequantize_q6k_row(dst, lm_bytes, row, hidden_dim),
                    QType::Q8_0 => dequantize_q8_0_row(dst, lm_bytes, row, hidden_dim),
                }
            }
            drop(lm_w);
            self.lm_head_fp32 = Some(fp32);
        }

        if let Some(lm_fp32) = self.lm_head_fp32.as_ref() {
            // FP32 × FP32 path. Bit-equivalent to Aether's
            // `lmHeadCache: Float32Array` + `forwardMatvecF32` route.
            // We borrow lm_fp32 immutably so we can keep `&mut self`
            // for the logits buffer.
            if seq_len == 1 {
                matvec_memo::cached_mat_vec_f32(
                    &mut self.memo,
                    &mut self.batch_logits[..cfg.vocab_size],
                    &self.batch_xb[..hidden_dim],
                    lm_fp32,
                    cfg.vocab_size,
                    hidden_dim,
                    1,
                    cfg.vocab_size,
                    cfg.num_layers,
                    matvec_memo::OP_LM_HEAD,
                    gemma_mat_vec_f32_dispatch_batch,
                );
            } else {
                matvec_memo::cached_mat_vec_f32(
                    &mut self.memo,
                    &mut self.batch_logits,
                    &self.batch_xb,
                    lm_fp32,
                    cfg.vocab_size,
                    hidden_dim,
                    seq_len,
                    cfg.vocab_size,
                    cfg.num_layers,
                    matvec_memo::OP_LM_HEAD,
                    gemma_mat_vec_f32_dispatch_batch,
                );
            }
        } else {
            // Legacy on-the-fly Q4_K path. Required for CF Workers
            // trisplit (128 MiB cap can't hold a 5.6 GiB FP32 cache).
            let lm_w = self
                .knot
                .backend
                .fetch_tensor(&self.locs.lm_head.name)
                .map_err(|e| format!("fetch lm_head: {:?}", e))?;
            matvec_memo::cached_mat_vec(
                &mut self.memo,
                &mut self.batch_logits,
                &self.batch_xb,
                &lm_w,
                self.locs.lm_head.qtype,
                cfg.vocab_size,
                hidden_dim,
                seq_len,
                cfg.vocab_size,
                cfg.num_layers,
                matvec_memo::OP_LM_HEAD,
                mat_vec_dispatch_batch,
            );
            drop(lm_w);
        }

        // GEMMA4_DBG: pre-softcap logits health for the LAST token. A huge
        // `max=` or nonzero nan/inf here, when the END-OF-LAYER residual lines
        // above were bounded, would point the bug at the final-norm / lm-head
        // stage rather than the per-layer forward.
        #[cfg(not(target_arch = "wasm32"))]
        if gemma4_dbg() {
            let last = (seq_len - 1) * cfg.vocab_size;
            let logits = &self.batch_logits[last..last + cfg.vocab_size];
            let (lmax, lnan, linf) = g4_stats(logits);
            // Top-3 argmax (tanh softcap is monotonic, so pre-softcap argmax ==
            // final argmax). If the forward is CORRECT, a 'capital of France'
            // prompt's top token is gemma4-12b 'Paris' (id 50429); a wrong id
            // here proves a forward-correctness bug (not decode/tokenizer).
            let mut top: [(usize, f32); 3] = [(0, f32::NEG_INFINITY); 3];
            for (i, &v) in logits.iter().enumerate() {
                if v > top[2].1 {
                    top[2] = (i, v);
                    top.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap_or(std::cmp::Ordering::Equal));
                }
            }
            eprintln!(
                "[g4dbg] lm_head pre-softcap logits max={lmax:.4e} nan={lnan} inf={linf} \
                 vocab={} top3=[{}:{:.3}, {}:{:.3}, {}:{:.3}]",
                cfg.vocab_size,
                top[0].0, top[0].1, top[1].0, top[1].1, top[2].0, top[2].1
            );
        }

        // Tanh logit softcap (Gemma4: 30.0). Without this, argmax picks
        // garbage tokens because logits explode uncapped.
        if let Some(cap) = cfg.final_logit_softcap {
            let last = (seq_len - 1) * cfg.vocab_size;
            tanh_softcap(&mut self.batch_logits[last..last + cfg.vocab_size], cap);
        }

        let last = (seq_len - 1) * cfg.vocab_size;
        let mut out = vec![0.0f32; cfg.vocab_size];
        out.copy_from_slice(&self.batch_logits[last..last + cfg.vocab_size]);
        Ok(out)
    }
}

// Trait visibility helper: re-export the resolve_all so the sibling module
// doesn't need to duplicate the tensor-name table. The `pub(crate)` version
// in model.rs handles this directly; here we just call out the dependency.
